// Auto-generated — do not edit. Run scripts/fetchExercises.mjs to regenerate.
// 212 exercises (dumbbell, resistance band, body weight) from free-exercise-db.
const EXERCISE_LIBRARY = [{"id":"3_4_Sit-Up","name":"3/4 Sit-Up","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie down on the floor and secure your feet. Your legs should be bent at the knees.","Place your hands behind or to the side of your head. You will begin with your back on the ground. This will be your starting position.","Flex your hips and spine to raise your torso toward your knees.","At the top of the contraction your torso should be perpendicular to the ground. Reverse the motion, going only ¾ of the way down.","Repeat for the recommended amount of repetitions."],"images":["3_4_Sit-Up/0.jpg","3_4_Sit-Up/1.jpg"]},{"id":"Air_Bike","name":"Air Bike","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put your hands beside your head. Be careful however to not strain with the neck as you perform it. Now lift your shoulders into the crunch position.","Bring knees up to where they are perpendicular to the floor, with your lower legs parallel to the floor. This will be your starting position.","Now simultaneously, slowly go through a cycle pedal motion kicking forward with the right leg and bringing in the knee of the left leg. Bring your right elbow close to your left knee by crunching to the side, as you breathe out.","Go back to the initial position as you breathe in.","Crunch to the opposite side as you cycle your legs and bring closer your left elbow to your right knee and exhale.","Continue alternating in this manner until all of the recommended repetitions for each side have been completed."],"images":["Air_Bike/0.jpg","Air_Bike/1.jpg"]},{"id":"Alternate_Hammer_Curl","name":"Alternate Hammer Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.","The palms of the hands should be facing your torso. This will be your starting position.","While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat the movement with the left hand. This equals one repetition.","Continue alternating in this manner for the recommended amount of repetitions."],"images":["Alternate_Hammer_Curl/0.jpg","Alternate_Hammer_Curl/1.jpg"]},{"id":"Alternate_Heel_Touchers","name":"Alternate Heel Touchers","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie on the floor with the knees bent and the feet on the floor around 18-24 inches apart. Your arms should be extended by your side. This will be your starting position.","Crunch over your torso forward and up about 3-4 inches to the right side and touch your right heel as you hold the contraction for a second. Exhale while performing this movement.","Now go back slowly to the starting position as you inhale.","Now crunch over your torso forward and up around 3-4 inches to the left side and touch your left heel as you hold the contraction for a second. Exhale while performing this movement and then go back to the starting position as you inhale. Now that both heels have been touched, that is considered 1 repetition.","Continue alternating sides in this manner until all prescribed repetitions are done."],"images":["Alternate_Heel_Touchers/0.jpg","Alternate_Heel_Touchers/1.jpg"]},{"id":"Alternate_Incline_Dumbbell_Curl","name":"Alternate Incline Dumbbell Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Sit down on an incline bench with a dumbbell in each hand being held at arms length. Tip: Keep the elbows close to the torso.This will be your starting position.","While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. As you do so, rotate the hand so that the palm is facing up. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.","Slowly begin to bring the dumbbell back to starting position as your breathe in.","Repeat the movement with the left hand. This equals one repetition.","Continue alternating in this manner for the recommended amount of repetitions."],"images":["Alternate_Incline_Dumbbell_Curl/0.jpg","Alternate_Incline_Dumbbell_Curl/1.jpg"]},{"id":"Alternating_Deltoid_Raise","name":"Alternating Deltoid Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["In a standing position, hold a pair of dumbbells at your side.","Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.","Return the weights to your side.","On the next repetition, raise the weights laterally, raising them out to your side to about shoulder height.","Return the weights to the starting position and continue alternating to the front and side."],"images":["Alternating_Deltoid_Raise/0.jpg","Alternating_Deltoid_Raise/1.jpg"]},{"id":"Arnold_Dumbbell_Press","name":"Arnold Dumbbell Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Sit on an exercise bench with back support and hold two dumbbells in front of you at about upper chest level with your palms facing your body and your elbows bent. Tip: Your arms should be next to your torso. The starting position should look like the contracted portion of a dumbbell curl.","Now to perform the movement, raise the dumbbells as you rotate the palms of your hands until they are facing forward.","Continue lifting the dumbbells until your arms are extended above you in straight arm position. Breathe out as you perform this portion of the movement.","After a second pause at the top, begin to lower the dumbbells to the original position by rotating the palms of your hands towards you. Tip: The left arm will be rotated in a counter clockwise manner while the right one will be rotated clockwise. Breathe in as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],"images":["Arnold_Dumbbell_Press/0.jpg","Arnold_Dumbbell_Press/1.jpg"]},{"id":"Around_The_Worlds","name":"Around The Worlds","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders"],"instructions":["Lay down on a flat bench holding a dumbbell in each hand with the palms of the hands facing towards the ceiling. Tip: Your arms should be parallel to the floor and next to your thighs. To avoid injury, make sure that you keep your elbows slightly bent. This will be your starting position.","Now move the dumbbells by creating a semi-circle as you displace them from the initial position to over the head. All of the movement should happen with the arms parallel to the floor at all times. Breathe in as you perform this portion of the movement.","Reverse the movement to return the weight to the starting position as you exhale."],"images":["Around_The_Worlds/0.jpg","Around_The_Worlds/1.jpg"]},{"id":"Back_Flyes_-_With_Bands","name":"Back Flyes - With Bands","equipment":"bands","primaryMuscles":["shoulders"],"secondaryMuscles":["middle back","triceps"],"instructions":["Run a band around a stationary post like that of a squat rack.","Grab the band by the handles and stand back so that the tension in the band rises.","Extend and lift the arms straight in front of you. Tip: Your arms should be straight and parallel to the floor while perpendicular to your torso. Your feet should be firmly planted on the floor spread at shoulder width. This will be your starting position.","As you exhale, move your arms to the sides and back. Keep your arms extended and parallel to the floor. Continue the movement until the arms are extended to your sides.","After a pause, go back to the original position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Back_Flyes_-_With_Bands/0.jpg","Back_Flyes_-_With_Bands/1.jpg"]},{"id":"Band_Hip_Adductions","name":"Band Hip Adductions","equipment":"bands","primaryMuscles":["adductors"],"secondaryMuscles":[],"instructions":["Anchor a band around a solid post or other object.","Stand with your left side to the post, and put your right foot through the band, getting it around the ankle.","Stand up straight and hold onto the post if needed. This will be your starting position.","Keeping the knee straight, raise your right legs out to the side as far as you can.","Return to the starting position and repeat for the desired rep count.","Switch sides."],"images":["Band_Hip_Adductions/0.jpg","Band_Hip_Adductions/1.jpg"]},{"id":"Band_Pull_Apart","name":"Band Pull Apart","equipment":"bands","primaryMuscles":["shoulders"],"secondaryMuscles":["middle back","traps"],"instructions":["Begin with your arms extended straight out in front of you, holding the band with both hands.","Initiate the movement by performing a reverse fly motion, moving your hands out laterally to your sides.","Keep your elbows extended as you perform the movement, bringing the band to your chest. Ensure that you keep your shoulders back during the exercise.","Pause as you complete the movement, returning to the starting position under control."],"images":["Band_Pull_Apart/0.jpg","Band_Pull_Apart/1.jpg"]},{"id":"Band_Skull_Crusher","name":"Band Skull Crusher","equipment":"bands","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Secure a band to the base of a rack or the bench. Lay on the bench so that the band is lined up with your head.","Take hold of the band, raising your elbows so that the upper arm is perpendicular to the floor. With the elbow flexed, the band should be above your head. This will be your starting position.","Extend through the elbow to straighten your arm, keeping your upper arm in place. Pause at the top of the motion, and return to the starting position."],"images":["Band_Skull_Crusher/0.jpg","Band_Skull_Crusher/1.jpg"]},{"id":"Bench_Dips","name":"Bench Dips","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["For this exercise you will need to place a bench behind your back. With the bench perpendicular to your body, and while looking away from it, hold on to the bench on its edge with the hands fully extended, separated at shoulder width. The legs will be extended forward, bent at the waist and perpendicular to your torso. This will be your starting position.","Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down.","Using your triceps to bring your torso up again, lift yourself back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Bench_Dips/0.jpg","Bench_Dips/1.jpg"]},{"id":"Bench_Press_-_With_Bands","name":"Bench Press - With Bands","equipment":"bands","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Using a flat bench secure a band under the leg of the bench that is nearest to your head.","Once the band is secure, grab it by both handles and lie down on the bench.","Extend your arms so that you are holding the band handles in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","Bring down the handles slowly until your elbow forms a 90 degree angle. Keep full control at all times.","As you breathe out, bring the handles up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions of your training program."],"images":["Bench_Press_-_With_Bands/0.jpg","Bench_Press_-_With_Bands/1.jpg"]},{"id":"Bent_Over_Dumbbell_Rear_Delt_Raise_With_Head_On_Bench","name":"Bent Over Dumbbell Rear Delt Raise With Head On Bench","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Stand up straight while holding a dumbbell in each hand and with an incline bench in front of you.","While keeping your back straight and maintaining the natural arch of your back, lean forward until your forehead touches the bench in front of you. Let the arms hang in front of you perpendicular to the ground. The palms of your hands should be facing each other and your torso should be parallel to the floor. This will be your starting position.","Keeping your torso forward and stationary, and the arms straight with a slight bend at the elbows, lift the dumbbells straight to the side until both arms are parallel to the floor. Exhale as you lift the weights. Caution: avoid swinging the torso or bringing the arms back as opposed to the side.","After a one second contraction at the top, slowly lower the dumbbells back to the starting position.","Repeat the recommended amount of repetitions."],"images":["Bent_Over_Dumbbell_Rear_Delt_Raise_With_Head_On_Bench/0.jpg","Bent_Over_Dumbbell_Rear_Delt_Raise_With_Head_On_Bench/1.jpg"]},{"id":"Bent_Over_Two-Dumbbell_Row","name":"Bent Over Two-Dumbbell Row","equipment":"dumbbell","primaryMuscles":["middle back"],"secondaryMuscles":["biceps","lats","shoulders"],"instructions":["With a dumbbell in each hand (palms facing your torso), bend your knees slightly and bring your torso forward by bending at the waist; as you bend make sure to keep your back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.","While keeping the torso stationary, lift the dumbbells to your side (as you breathe out), keeping the elbows close to the body (do not exert any force with the forearm other than holding the weights). On the top contracted position, squeeze the back muscles and hold for a second.","Slowly lower the weight again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Bent_Over_Two-Dumbbell_Row/0.jpg","Bent_Over_Two-Dumbbell_Row/1.jpg"]},{"id":"Bent_Over_Two-Dumbbell_Row_With_Palms_In","name":"Bent Over Two-Dumbbell Row With Palms In","equipment":"dumbbell","primaryMuscles":["middle back"],"secondaryMuscles":["biceps","lats"],"instructions":["With a dumbbell in each hand (palms facing each other), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.","While keeping the torso stationary, lift the dumbbells to your side as you breathe out, squeezing your shoulder blades together. On the top contracted position, squeeze the back muscles and hold for a second.","Slowly lower the weight again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Bent_Over_Two-Dumbbell_Row_With_Palms_In/0.jpg","Bent_Over_Two-Dumbbell_Row_With_Palms_In/1.jpg"]},{"id":"Bent-Arm_Dumbbell_Pullover","name":"Bent-Arm Dumbbell Pullover","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["lats","shoulders","triceps"],"instructions":["Place a dumbbell standing up on a flat bench.","Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.","Grasp the dumbbell with both hands and hold it straight over your chest with a bend in your arms. Both palms should be pressing against the underside one of the sides of the dumbbell. This will be your starting position. Caution: Always ensure that the dumbbell used for this exercise is secure. Using a dumbbell with loose plates can result in the dumbbell falling apart and falling on your face.","While keeping your arms locked in the bent arm position, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.","At that point, bring the dumbbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.","Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions."],"images":["Bent-Arm_Dumbbell_Pullover/0.jpg","Bent-Arm_Dumbbell_Pullover/1.jpg"]},{"id":"Bent-Knee_Hip_Raise","name":"Bent-Knee Hip Raise","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lay flat on the floor with your arms next to your sides.","Now bend your knees at around a 75 degree angle and lift your feet off the floor by around 2 inches.","Using your lower abs, bring your knees in towards you as you maintain the 75 degree angle bend in your legs. Continue this movement until you raise your hips off of the floor by rolling your pelvis backward. Breathe out as you perform this portion of the movement. Tip: At the end of the movement your knees will be over your chest.","Squeeze your abs at the top of the movement for a second and then return to the starting position slowly as you breathe in. Tip: Maintain a controlled motion at all times.","Repeat for the recommended amount of repetitions."],"images":["Bent-Knee_Hip_Raise/0.jpg","Bent-Knee_Hip_Raise/1.jpg"]},{"id":"Body_Tricep_Press","name":"Body Tricep Press","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Position a bar in a rack at chest height.","Standing, take a shoulder width grip on the bar and step a yard or two back, feet together and arms extended so that you are leaning on the bar. This will be your starting position.","Begin by flexing the elbow, lowering yourself towards the bar.","Pause, and then reverse the motion by extending the elbows.","Progress from bodyweight by adding chains over your shoulders."],"images":["Body_Tricep_Press/0.jpg","Body_Tricep_Press/1.jpg"]},{"id":"Body-Up","name":"Body-Up","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":["abdominals","forearms"],"instructions":["Assume a plank position on the ground. You should be supporting your bodyweight on your toes and forearms, keeping your torso straight. Your forearms should be shoulder-width apart. This will be your starting position.","Pressing your palms firmly into the ground, extend through the elbows to raise your body from the ground. Keep your torso rigid as you perform the movement.","Slowly lower your forearms back to the ground by allowing the elbows to flex.","Repeat."],"images":["Body-Up/0.jpg","Body-Up/1.jpg"]},{"id":"Bodyweight_Squat","name":"Bodyweight Squat","equipment":"body weight","primaryMuscles":["quadriceps"],"secondaryMuscles":["glutes","hamstrings"],"instructions":["Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position.","Begin the movement by flexing your knees and hips, sitting back with your hips.","Continue down to full depth if you are able,and quickly reverse the motion until you return to the starting position. As you squat, keep your head and chest up and push your knees out."],"images":["Bodyweight_Squat/0.jpg","Bodyweight_Squat/1.jpg"]},{"id":"Bottoms_Up","name":"Bottoms Up","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Begin by lying on your back on the ground. Your legs should be straight and your arms at your side. This will be your starting position.","To perform the movement, tuck the knees toward your chest by flexing the hips and knees. Following this, extend your legs directly above you so that they are perpendicular to the ground. Rotate and elevate your pelvis to raise your glutes from the floor.","After a brief pause, return to the starting position."],"images":["Bottoms_Up/0.jpg","Bottoms_Up/1.jpg"]},{"id":"Butt_Lift_Bridge","name":"Butt Lift (Bridge)","equipment":"body weight","primaryMuscles":["glutes"],"secondaryMuscles":["hamstrings"],"instructions":["Lie flat on the floor on your back with the hands by your side and your knees bent. Your feet should be placed around shoulder width. This will be your starting position.","Pushing mainly with your heels, lift your hips off the floor while keeping your back straight. Breathe out as you perform this part of the motion and hold at the top for a second.","Slowly go back to the starting position as you breathe in."],"images":["Butt_Lift_Bridge/0.jpg","Butt_Lift_Bridge/1.jpg"]},{"id":"Butt-Ups","name":"Butt-Ups","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Begin a pushup position but with your elbows on the ground and resting on your forearms. Your arms should be bent at a 90 degree angle.","Arch your back slightly out rather than keeping your back completely straight.","Raise your glutes toward the ceiling, squeezing your abs tightly to close the distance between your ribcage and hips. The end result will be that you'll end up in a high bridge position. Exhale as you perform this portion of the movement.","Lower back down slowly to your starting position as you breathe in. Tip: Don't let your back sag downwards.","Repeat for the recommended amount of repetitions."],"images":["Butt-Ups/0.jpg","Butt-Ups/1.jpg"]},{"id":"Calf_Raise_On_A_Dumbbell","name":"Calf Raise On A Dumbbell","equipment":"dumbbell","primaryMuscles":["calves"],"secondaryMuscles":[],"instructions":["Hang on to a sturdy object for balance and stand on a dumbbell handle, preferably one with round plates so that it rolls as in this manner you have to work harder to stabilize yourself; thus increasing the effectiveness of the exercise.","Now roll your foot slightly forward so that you can get a nice stretch of the calf. This will be your starting position.","Lift the calf as you roll your foot over the top of the handle so that you get a full extension. Exhale during the execution of this movement. Contract the calf hard at the top and hold for a second. Tip: As you come up, roll the dumbbell slightly backward.","Now inhale as you roll the dumbbell slightly forward as you come down to get a better stretch.","Repeat for the recommended amount of repetitions."],"images":["Calf_Raise_On_A_Dumbbell/0.jpg","Calf_Raise_On_A_Dumbbell/1.jpg"]},{"id":"Calf_Raises_-_With_Bands","name":"Calf Raises - With Bands","equipment":"bands","primaryMuscles":["calves"],"secondaryMuscles":[],"instructions":["Grab an exercise band and stand on it with your toes making sure that the length of the band between the foot and the arms is the same for both sides.","While holding the handles of the band, raise the arms to the side of your head as if you were getting ready to perform a shoulder press. The palms should be facing forward with the elbows bent and to the sides. This movement will create tension on the band. This will be your starting position.","Keeping the hands by your shoulder, stand up on your toes as you exhale and contract the calves hard at the top of the movement.","After a one second contraction, slowly go back down to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Calf_Raises_-_With_Bands/0.jpg","Calf_Raises_-_With_Bands/1.jpg"]},{"id":"Chin-Up","name":"Chin-Up","equipment":"body weight","primaryMuscles":["lats"],"secondaryMuscles":["biceps","forearms","middle back"],"instructions":["Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.","As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.","As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.","After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.","Repeat this motion for the prescribed amount of repetitions."],"images":["Chin-Up/0.jpg","Chin-Up/1.jpg"]},{"id":"Clock_Push-Up","name":"Clock Push-Up","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Move into a prone position on the floor, supporting your weight on your hands and toes.","Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.","Descend by flexing at the elbow, lowering your chest toward the ground.","At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible until you are air borne. Aim to \"jump\" 12-18 inches to one side.","As you accelerate up, move your outside foot away from your direction of travel. Leaving the ground, shift your body about 30 degrees for the next repetition.","Return to the starting position and repeat the exercise, working all the way around until you are back where you started."],"images":["Clock_Push-Up/0.jpg","Clock_Push-Up/1.jpg"]},{"id":"Close-Grip_Dumbbell_Press","name":"Close-Grip Dumbbell Press","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["Place a dumbbell standing up on a flat bench.","Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench with only your shoulders lying on the surface. Hips should be below the bench and your legs bent with your feet firmly on the floor.","Grasp the dumbbell with both hands and hold it straight over your chest at arm's length. Both palms should be pressing against the underside of the sides of the dumbbell. This will be your starting position.","Initiate the movement by lowering the dumbbell to your chest.","Return to the starting position by extending the elbows."],"images":["Close-Grip_Dumbbell_Press/0.jpg","Close-Grip_Dumbbell_Press/1.jpg"]},{"id":"Close-Grip_Push-Up_off_of_a_Dumbbell","name":"Close-Grip Push-Up off of a Dumbbell","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":["abdominals","chest","shoulders"],"instructions":["Lie on the floor and place your hands on an upright dumbbell. Supporting your weight on your toes and hands, keep your torso rigid and your elbows in with your arms straight. This will be your starting position.","Lower your body, allowing the elbows to flex while you inhale. Keep your body straight, not allowing your hips to rise or sag.","Press yourself back up to the starting position by extending the elbows. Breathe out as you perform this step.","After a pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],"images":["Close-Grip_Push-Up_off_of_a_Dumbbell/0.jpg","Close-Grip_Push-Up_off_of_a_Dumbbell/1.jpg"]},{"id":"Cocoons","name":"Cocoons","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Begin by lying on your back on the ground. Your legs should be straight and your arms extended behind your head. This will be your starting position.","To perform the movement, tuck the knees toward your chest, rotating your pelvis to lift your glutes from the floor. As you do so, flex the spine, bringing your arms back over your head to perform a simultaneous crunch motion.","After a brief pause, return to the starting position."],"images":["Cocoons/0.jpg","Cocoons/1.jpg"]},{"id":"Concentration_Curls","name":"Concentration Curls","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Sit down on a flat bench with one dumbbell in front of you between your legs. Your legs should be spread with your knees bent and feet on the floor.","Use your right arm to pick the dumbbell up. Place the back of your right upper arm on the top of your inner right thigh. Rotate the palm of your hand until it is facing forward away from your thigh. Tip: Your arm should be extended and the dumbbell should be above the floor. This will be your starting position.","While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: At the top of the movement make sure that the little finger of your arm is higher than your thumb. This guarantees a good contraction. Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to starting position as your breathe in. Caution: Avoid swinging motions at any time.","Repeat for the recommended amount of repetitions. Then repeat the movement with the left arm."],"images":["Concentration_Curls/0.jpg","Concentration_Curls/1.jpg"]},{"id":"Cross_Body_Hammer_Curl","name":"Cross Body Hammer Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Stand up straight with a dumbbell in each hand. Your hands should be down at your side with your palms facing in.","While keeping your palms facing in and without twisting your arm, curl the dumbbell of the right arm up towards your left shoulder as you exhale. Touch the top of the dumbbell to your shoulder and hold the contraction for a second.","Slowly lower the dumbbell along the same path as you inhale and then repeat the same movement for the left arm.","Continue alternating in this fashion until the recommended amount of repetitions is performed for each arm."],"images":["Cross_Body_Hammer_Curl/0.jpg","Cross_Body_Hammer_Curl/1.jpg"]},{"id":"Cross_Over_-_With_Bands","name":"Cross Over - With Bands","equipment":"bands","primaryMuscles":["chest"],"secondaryMuscles":["biceps","shoulders"],"instructions":["Secure an exercise band around a stationary post.","While facing away from the post, grab the handles on both ends of the band and step forward enough to create tension on the band.","Raise your arms to the sides, parallel to the floor, perpendicular to your torso (your torso and the arms should resemble the letter \"T\") and with the palms facing forward. Have them extended with a slight bend at the elbows. This will be your starting position.","While keeping your arms straight, bring them across your chest in a semicircular motion to the front as you exhale and flex your pecs. Hold the contraction for a second.","Slowly return to the starting position as you inhale.","Perform for the recommended amount of repetitions."],"images":["Cross_Over_-_With_Bands/0.jpg","Cross_Over_-_With_Bands/1.jpg"]},{"id":"Cross-Body_Crunch","name":"Cross-Body Crunch","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie flat on your back and bend your knees about 60 degrees.","Keep your feet flat on the floor and place your hands loosely behind your head. This will be your starting position.","Now curl up and bring your right elbow and shoulder across your body while bring your left knee in toward your left shoulder at the same time. Reach with your elbow and try to touch your knee. Exhale as you perform this movement. Tip: Try to bring your shoulder up towards your knee rather than just your elbow and remember that the key is to contract the abs as you perform the movement; not just to move the elbow.","Now go back down to the starting position as you inhale and repeat with the left elbow and the right knee.","Continue alternating in this manner until all prescribed repetitions are done."],"images":["Cross-Body_Crunch/0.jpg","Cross-Body_Crunch/1.jpg"]},{"id":"Crunch_-_Hands_Overhead","name":"Crunch - Hands Overhead","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie on the floor with your back flat and knees bent with around a 60-degree angle between the hamstrings and the calves.","Keep your feet flat on the floor and stretch your arms overhead with your palms crossed. This will be your starting position.","Curl your upper body forward and bring your shoulder blades just off the floor. At all times, keep your arms aligned with your head, neck and shoulder. Don't move them forward from that position. Exhale as you perform this portion of the movement and hold the contraction for a second.","Slowly lower down to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Crunch_-_Hands_Overhead/0.jpg","Crunch_-_Hands_Overhead/1.jpg"]},{"id":"Crunch_-_Legs_On_Exercise_Ball","name":"Crunch - Legs On Exercise Ball","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie flat on your back with your feet resting on an exercise ball and your knees bent at a 90 degree angle.","Place your feet three to four inches apart and point your toes inward so they touch.","Place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.","Push the small of your back down in the floor in order to better isolate your abdominal muscles. This will be your starting position.","Begin to roll your shoulders off the floor and continue to push down as hard as you can with your lower back. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. Breathe out as you execute this portion of the movement. Squeeze your abdominals hard at the top of the contraction and hold for a second. Tip: Focus on a slow, controlled movement. Refrain from using momentum at any time.","Slowly go back down to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Crunch_-_Legs_On_Exercise_Ball/0.jpg","Crunch_-_Legs_On_Exercise_Ball/1.jpg"]},{"id":"Crunches","name":"Crunches","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie flat on your back with your feet flat on the ground, or resting on a bench with your knees bent at a 90 degree angle. If you are resting your feet on a bench, place them three to four inches apart and point your toes inward so they touch.","Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.","While pushing the small of your back down in the floor to better isolate your abdominal muscles, begin to roll your shoulders off the floor.","Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don't cheat yourself by using momentum.","After the one second contraction, begin to come down slowly again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Crunches/0.jpg","Crunches/1.jpg"]},{"id":"Cuban_Press","name":"Cuban Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["traps"],"instructions":["Take a dumbbell in each hand with a pronated grip in a standing position. Raise your upper arms so that they are parallel to the floor, allowing your lower arms to hang in the \"scarecrow\" position. This will be your starting position.","To initiate the movement, externally rotate the shoulders to move the upper arm 180 degrees. Keep the upper arms in place, rotating the upper arms until the wrists are directly above the elbows, the forearms perpendicular to the floor.","Now press the dumbbells by extending at the elbows, straightening your arms overhead.","Return to the starting position as you breathe in by reversing the steps.","Repeat for the recommended amount of repetitions."],"images":["Cuban_Press/0.jpg","Cuban_Press/1.jpg"]},{"id":"Dead_Bug","name":"Dead Bug","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Begin lying on your back with your hands extended above you toward the ceiling.","Bring your feet, knees, and hips up to 90 degrees.","Exhale hard to bring your ribcage down and flatten your back onto the floor, rotating your pelvis up and squeezing your glutes. Hold this position throughout the movement. This will be your starting position.","Initiate the exercise by extending one leg, straightening the knee and hip to bring the leg just above the ground.","Maintain the position of your lumbar and pelvis as you perform the movement, as your back is going to want to arch.","Stay tight and return the working leg to the starting position.","Repeat on the opposite side, alternating until the set is complete."],"images":["Dead_Bug/0.jpg","Dead_Bug/1.jpg"]},{"id":"Decline_Crunch","name":"Decline Crunch","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Secure your legs at the end of the decline bench and lie down.","Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.","While pushing the small of your back down in the bench to better isolate your abdominal muscles, begin to roll your shoulders off it.","Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the bench only about four inches, and your lower back should remain on the bench. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don't cheat yourself by using momentum.","After the one second contraction, begin to come down slowly again to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Decline_Crunch/0.jpg","Decline_Crunch/1.jpg"]},{"id":"Decline_Dumbbell_Bench_Press","name":"Decline Dumbbell Bench Press","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","Once you are laying down, move the dumbbells in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","Bring down the weights slowly to your side as you breathe out. Keep full control of the dumbbells at all times. Tip: Throughout the motion, the forearms should always be perpendicular to the floor.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up..","Repeat the movement for the prescribed amount of repetitions of your training program."],"images":["Decline_Dumbbell_Bench_Press/0.jpg","Decline_Dumbbell_Bench_Press/1.jpg"]},{"id":"Decline_Dumbbell_Flyes","name":"Decline Dumbbell Flyes","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":[],"instructions":["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.","With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.","Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.","Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions."],"images":["Decline_Dumbbell_Flyes/0.jpg","Decline_Dumbbell_Flyes/1.jpg"]},{"id":"Decline_Dumbbell_Triceps_Extension","name":"Decline Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.","As you breathe in and you keep the upper arms stationary (and elbows in), bring the dumbbells down slowly by moving your forearms in a semicircular motion towards you until your thumbs are next to your ears. Breathe in as you perform this portion of the movement.","Lift the dumbbells back to the starting position by contracting the triceps and exhaling.","Repeat for the recommended amount of repetitions."],"images":["Decline_Dumbbell_Triceps_Extension/0.jpg","Decline_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"Decline_Oblique_Crunch","name":"Decline Oblique Crunch","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Secure your legs at the end of the decline bench and slowly lay down on the bench.","Raise your upper body off the bench until your torso is about 35-45 degrees if measured from the floor.","Put one hand beside your head and the other on your thigh. This will be your starting position.","Raise your upper body slowly from the starting position while turning your torso to the left. Continue crunching up as you exhale until your right elbow touches your left knee. Hold this contracted position for a second. Tip: Focus on keeping your abs tight and keeping the movement slow and controlled.","Lower your body back down slowly to the starting position as you inhale.","After completing one set on the right for the recommended amount of repetitions, switch to your left side. Tip: Focus on really twisting your torso and feeling the contraction when you are in the up position."],"images":["Decline_Oblique_Crunch/0.jpg","Decline_Oblique_Crunch/1.jpg"]},{"id":"Decline_Reverse_Crunch","name":"Decline Reverse Crunch","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie on your back on a decline bench and hold on to the top of the bench with both hands. Don't let your body slip down from this position.","Hold your legs parallel to the floor using your abs to hold them there while keeping your knees and feet together. Tip: Your legs should be fully extended with a slight bend on the knee. This will be your starting position.","While exhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the bench. At the end of this movement your knees will be touching your chest.","Hold the contraction for a second and move your legs back to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],"images":["Decline_Reverse_Crunch/0.jpg","Decline_Reverse_Crunch/1.jpg"]},{"id":"Dips_-_Triceps_Version","name":"Dips - Triceps Version","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["To get into the starting position, hold your body at arm's length with your arms nearly locked above the bars.","Now, inhale and slowly lower yourself downward. Your torso should remain upright and your elbows should stay close to your body. This helps to better focus on tricep involvement. Lower yourself until there is a 90 degree angle formed between the upper arm and forearm.","Then, exhale and push your torso back up using your triceps to bring your body back to the starting position.","Repeat the movement for the prescribed amount of repetitions."],"images":["Dips_-_Triceps_Version/0.jpg","Dips_-_Triceps_Version/1.jpg"]},{"id":"Dumbbell_Alternate_Bicep_Curl","name":"Dumbbell Alternate Bicep Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Stand (torso upright) with a dumbbell in each hand held at arms length. The elbows should be close to the torso and the palms of your hand should be facing your thighs.","While holding the upper arm stationary, curl the right weight as you rotate the palm of the hands until they are facing forward. At this point continue contracting the biceps as you breathe out until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.","Slowly begin to bring the dumbbell back to the starting position as your breathe in. Tip: Remember to twist the palms back to the starting position (facing your thighs) as you come down.","Repeat the movement with the left hand. This equals one repetition.","Continue alternating in this manner for the recommended amount of repetitions."],"images":["Dumbbell_Alternate_Bicep_Curl/0.jpg","Dumbbell_Alternate_Bicep_Curl/1.jpg"]},{"id":"Dumbbell_Bench_Press","name":"Dumbbell Bench Press","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie down on a flat bench with a dumbbell in each hand resting on top of your thighs. The palms of your hands will be facing each other.","Then, using your thighs to help raise the dumbbells up, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. The dumbbells should be just to the sides of your chest, with your upper arm and forearm creating a 90 degree angle. Be sure to maintain full control of the dumbbells at all times. This will be your starting position.","Then, as you breathe out, use your chest to push the dumbbells up. Lock your arms at the top of the lift and squeeze your chest, hold for a second and then begin coming down slowly. Tip: Ideally, lowering the weight should take about twice as long as raising it.","Repeat the movement for the prescribed amount of repetitions of your training program."],"images":["Dumbbell_Bench_Press/0.jpg","Dumbbell_Bench_Press/1.jpg"]},{"id":"Dumbbell_Bench_Press_with_Neutral_Grip","name":"Dumbbell Bench Press with Neutral Grip","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Take a dumbbell in each hand and lay back onto a flat bench. Your feet should be flat on the floor and your shoulder blades retracted.","Maintaining a neutral grip, palms facing each other, begin with your arms extended directly above you, perpendicular to the floor. This will be your starting position.","Begin the movement by flexing the elbow, lowering the upper arms to the side. Descend until the dumbbells are to your torso.","Pause, then extend the elbow and return to the starting position."],"images":["Dumbbell_Bench_Press_with_Neutral_Grip/0.jpg","Dumbbell_Bench_Press_with_Neutral_Grip/1.jpg"]},{"id":"Dumbbell_Bicep_Curl","name":"Dumbbell Bicep Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Stand up straight with a dumbbell in each hand at arm's length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Bicep_Curl/0.jpg","Dumbbell_Bicep_Curl/1.jpg"]},{"id":"Dumbbell_Clean","name":"Dumbbell Clean","equipment":"dumbbell","primaryMuscles":["hamstrings"],"secondaryMuscles":["calves","forearms","glutes","lower back","quadriceps","shoulders","traps"],"instructions":["Begin standing with a dumbbell in each hand with your feet shoulder width apart.","Lower the weights to the floor by flexing at the hips and knees, pushing your hips back until the dumbbells reach the floor. This will be your starting position.","To initiate the movement, violently jump upward by extending the hips, knees, and ankles to acclerate the weights upward. Maintaining a neutral grip on the dumbbells, keep the arms straight until full extension is reached.","After full extension, rebend the hips and knees to receive the weight in a squat position. Allow the arms to bend, guiding the dumbbells to your shoulders.","Upon receiving the weight in the squat position, extend the hips and knees to finish in a standing position with the weights on your shoulders."],"images":["Dumbbell_Clean/0.jpg","Dumbbell_Clean/1.jpg"]},{"id":"Dumbbell_Flyes","name":"Dumbbell Flyes","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":[],"instructions":["Lie down on a flat bench with a dumbbell on each hand resting on top of your thighs. The palms of your hand will be facing each other.","Then using your thighs to help raise the dumbbells, lift the dumbbells one at a time so you can hold them in front of you at shoulder width with the palms of your hands facing each other. Raise the dumbbells up like you're pressing them, but stop and hold just before you lock out. This will be your starting position.","With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.","Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.","Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions."],"images":["Dumbbell_Flyes/0.jpg","Dumbbell_Flyes/1.jpg"]},{"id":"Dumbbell_Incline_Row","name":"Dumbbell Incline Row","equipment":"dumbbell","primaryMuscles":["middle back"],"secondaryMuscles":["biceps","forearms","lats","shoulders"],"instructions":["Using a neutral grip, lean into an incline bench.","Take a dumbbell in each hand with a neutral grip, beginning with the arms straight. This will be your starting position.","Retract the shoulder blades and flex the elbows to row the dumbbells to your side.","Pause at the top of the motion, and then return to the starting position."],"images":["Dumbbell_Incline_Row/0.jpg","Dumbbell_Incline_Row/1.jpg"]},{"id":"Dumbbell_Incline_Shoulder_Raise","name":"Dumbbell Incline Shoulder Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Sit on an Incline Bench while holding a dumbbell on each hand on top of your thighs.","Lift your legs up to kick the weights to your shoulders and lean back. Position the dumbbells above your shoulders with your arms extended. The arms should be perpendicular to the floor with your palms facing forward and knuckles pointing towards the ceiling. This will be your starting position.","While keeping the arms straight and locked, lift the dumbbells by raising the shoulders from the bench as you breathe out.","Bring back the dumbbells to the starting position as you breathe in.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Incline_Shoulder_Raise/0.jpg","Dumbbell_Incline_Shoulder_Raise/1.jpg"]},{"id":"Dumbbell_Lunges","name":"Dumbbell Lunges","equipment":"dumbbell","primaryMuscles":["quadriceps"],"secondaryMuscles":["calves","glutes","hamstrings"],"instructions":["Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.","Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground.","Using mainly the heel of your foot, push up and go back to the starting position as you exhale.","Repeat the movement for the recommended amount of repetitions and then perform with the left leg."],"images":["Dumbbell_Lunges/0.jpg","Dumbbell_Lunges/1.jpg"]},{"id":"Dumbbell_Lying_One-Arm_Rear_Lateral_Raise","name":"Dumbbell Lying One-Arm Rear Lateral Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["middle back"],"instructions":["While holding a dumbbell in one hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench. The other hand can be used to hold to the leg of the bench for stability.","Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.","Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbell to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/0.jpg","Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/1.jpg"]},{"id":"Dumbbell_Lying_Pronation","name":"Dumbbell Lying Pronation","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Lie on a flat bench face down with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.","Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.","Now raise the upper arm so that the forearm is perpendicular to the floor and the upper arm is perpendicular to your torso. Tip: The upper arm should be parallel to the floor and also creating a 90-degree angle with your torso. This will be your starting position.","As you breathe out, externally rotate your forearm so that the dumbbell is lifted forward as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is parallel to the floor. At this point you will hold the contraction for a second.","As you breathe in, slowly go back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Lying_Pronation/0.jpg","Dumbbell_Lying_Pronation/1.jpg"]},{"id":"Dumbbell_Lying_Rear_Lateral_Raise","name":"Dumbbell Lying Rear Lateral Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["While holding a dumbbell in each hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench.","Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.","Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbells to the starting position as you inhale.","Repeat for the recommended amount of repetitions and then switch to the other arm."],"images":["Dumbbell_Lying_Rear_Lateral_Raise/0.jpg","Dumbbell_Lying_Rear_Lateral_Raise/1.jpg"]},{"id":"Dumbbell_Lying_Supination","name":"Dumbbell Lying Supination","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.","Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.","Now raise the upper arm so that the forearm is parallel to the floor and perpendicular to your torso (Tip: So the forearm will be directly in front of you). The upper arm will be stationary by your torso and should be parallel to the floor (aligned with your torso at all times). This will be your starting position.","As you breathe out, externally rotate your forearm so that the dumbbell is lifted up in a semicircle motion as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is perpendicular to the floor and the torso pointing towards the ceiling. At this point you will hold the contraction for a second.","As you breathe in, slowly go back to the starting position.","Repeat for the recommended amount of repetitions and then switch to the other arm."],"images":["Dumbbell_Lying_Supination/0.jpg","Dumbbell_Lying_Supination/1.jpg"]},{"id":"Dumbbell_One-Arm_Shoulder_Press","name":"Dumbbell One-Arm Shoulder Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.","Clean the dumbbell up to bring it to shoulder height. The other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface.","Rotate the wrist so that the palm of your hand is facing forward. This is your starting position.","As you exhale, push the dumbbell up until your arm is fully extended.","After a second pause, slowly come down back to the starting position as you inhale.","Repeat for the recommended amount of repetitions and then switch arms."],"images":["Dumbbell_One-Arm_Shoulder_Press/0.jpg","Dumbbell_One-Arm_Shoulder_Press/1.jpg"]},{"id":"Dumbbell_One-Arm_Triceps_Extension","name":"Dumbbell One-Arm Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.","Clean the dumbbell up to bring it to shoulder height and then extend the arm over your head so that the whole arm is perpendicular to the floor and next to your head. The dumbbell should be on top of you. The other hand can be kept fully extended to the side, by the waist, supporting the upper arm that has the dumbbell or grabbing a fixed surface.","Rotate the wrist so that the palm of your hand is facing forward and the pinkie is facing the ceiling. This will be your starting position.","Slowly lower the dumbbell behind your head as you hold the upper arm stationary. Inhale as you perform this movement and pause when your triceps are fully stretched.","Return to the starting position by flexing your triceps as you breathe out. Tip: It is imperative that only the forearm moves. The upper arm should remain at all times stationary next to your head.","Repeat for the recommended amount of repetitions and switch arms."],"images":["Dumbbell_One-Arm_Triceps_Extension/0.jpg","Dumbbell_One-Arm_Triceps_Extension/1.jpg"]},{"id":"Dumbbell_One-Arm_Upright_Row","name":"Dumbbell One-Arm Upright Row","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["biceps","traps"],"instructions":["Grab a dumbbell and stand up straight with your arm extended in front of you with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be resting on top of your thigh with the palm of your hands facing your thighs.","Keep the other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface. This will be your starting position.","Use your side shoulders to lift the dumbbell as you exhale. The dumbbell should be close to the body as you move it up. Continue to lift it until the dumbbell is nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the dumbbell back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions and switch arms."],"images":["Dumbbell_One-Arm_Upright_Row/0.jpg","Dumbbell_One-Arm_Upright_Row/1.jpg"]},{"id":"Dumbbell_Prone_Incline_Curl","name":"Dumbbell Prone Incline Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Grab a dumbbell on each hand and lie face down on an incline bench with your shoulders near top of the incline. Your knees can rest on the seat or your legs can be straddled to the sides (my preferred way).","Let your arms extend and hang naturally in front of you so that they are perpendicular to the floor.","Now keep your elbows in by your side and face the palms forward. This will be your starting position.","Raise the dumbbells by contracting the biceps until your arms are fully flexed. Exhale as you perform this portion of the movement and ensure that only the forearms move. The upper arms should remain stationary at all times.","Lower the dumbbells until your arms are fully extended.","Repeat for the recommended amount of times."],"images":["Dumbbell_Prone_Incline_Curl/0.jpg","Dumbbell_Prone_Incline_Curl/1.jpg"]},{"id":"Dumbbell_Raise","name":"Dumbbell Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["biceps"],"instructions":["Grab a dumbbell in each arm and stand up straight with your arms extended by your sides with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be next to your thighs with the palm of your hands facing back.","Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be to the side of the body as you move them up. Continue to lift it until the dumbbells are nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Raise/0.jpg","Dumbbell_Raise/1.jpg"]},{"id":"Dumbbell_Rear_Lunge","name":"Dumbbell Rear Lunge","equipment":"dumbbell","primaryMuscles":["quadriceps"],"secondaryMuscles":["calves","glutes","hamstrings"],"instructions":["Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.","Step backward with your right leg around two feet or so from the left foot and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Tip: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground. Keep the torso upright during the lunge; flexible hip flexors are important. A long lunge emphasizes the Gluteus Maximus; a short lunge emphasizes Quadriceps.","Push up and go back to the starting position as you exhale. Tip: Use the ball of your feet to push in order to accentuate the quadriceps. To focus on the glutes, press with your heels.","Now repeat with the opposite leg."],"images":["Dumbbell_Rear_Lunge/0.jpg","Dumbbell_Rear_Lunge/1.jpg"]},{"id":"Dumbbell_Scaption","name":"Dumbbell Scaption","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["traps"],"instructions":["This corrective exercise strengthens the muscles that stabilize your shoulder blade. Hold a light weight in each hand, hanging at your sides. Your thumbs should pointing up.","Begin the movement raising your arms out in front of you, about 30 degrees off center. Your arms should be fully extended as you perform the movement.","Continue until your arms are parallel to the ground, and then return to the starting position."],"images":["Dumbbell_Scaption/0.jpg","Dumbbell_Scaption/1.jpg"]},{"id":"Dumbbell_Seated_One-Leg_Calf_Raise","name":"Dumbbell Seated One-Leg Calf Raise","equipment":"dumbbell","primaryMuscles":["calves"],"secondaryMuscles":[],"instructions":["Place a block on the floor about 12 inches from a flat bench.","Sit on a flat bench and place a dumbbell on your upper left thigh about 3 inches above your knee.","Now place the ball of your left foot on the block. This will be your starting position.","Raise your toes up as high as possible as you exhale and you contract your calf muscle. Hold the contraction for a second.","Slowly return to the starting position, stretching as far down as possible.","Repeat for your prescribed number of repetitions and then repeat with the right leg."],"images":["Dumbbell_Seated_One-Leg_Calf_Raise/0.jpg","Dumbbell_Seated_One-Leg_Calf_Raise/1.jpg"]},{"id":"Dumbbell_Shoulder_Press","name":"Dumbbell Shoulder Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["While holding a dumbbell in each hand, sit on a military press bench or utility bench that has back support. Place the dumbbells upright on top of your thighs.","Now raise the dumbbells to shoulder height one at a time using your thighs to help propel them up into position.","Make sure to rotate your wrists so that the palms of your hands are facing forward. This is your starting position.","Now, exhale and push the dumbbells upward until they touch at the top.","Then, after a brief pause at the top contracted position, slowly lower the weights back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Shoulder_Press/0.jpg","Dumbbell_Shoulder_Press/1.jpg"]},{"id":"Dumbbell_Shrug","name":"Dumbbell Shrug","equipment":"dumbbell","primaryMuscles":["traps"],"secondaryMuscles":[],"instructions":["Stand erect with a dumbbell on each hand (palms facing your torso), arms extended on the sides.","Lift the dumbbells by elevating the shoulders as high as possible while you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the dumbbells. Only the shoulders should be moving up and down.","Lower the dumbbells back to the original position.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Shrug/0.jpg","Dumbbell_Shrug/1.jpg"]},{"id":"Dumbbell_Side_Bend","name":"Dumbbell Side Bend","equipment":"dumbbell","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Stand up straight while holding a dumbbell on the left hand (palms facing the torso) as you have the right hand holding your waist. Your feet should be placed at shoulder width. This will be your starting position.","While keeping your back straight and your head up, bend only at the waist to the right as far as possible. Breathe in as you bend to the side. Then hold for a second and come back up to the starting position as you exhale. Tip: Keep the rest of the body stationary.","Now repeat the movement but bending to the left instead. Hold for a second and come back to the starting position.","Repeat for the recommended amount of repetitions and then change hands."],"images":["Dumbbell_Side_Bend/0.jpg","Dumbbell_Side_Bend/1.jpg"]},{"id":"Dumbbell_Squat","name":"Dumbbell Squat","equipment":"dumbbell","primaryMuscles":["quadriceps"],"secondaryMuscles":["calves","glutes","hamstrings","lower back"],"instructions":["Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).","Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.","Begin to slowly lower your torso by bending the knees as you maintain a straight posture with the head up. Continue down until your thighs are parallel to the floor. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.","Begin to raise your torso as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Squat/0.jpg","Dumbbell_Squat/1.jpg"]},{"id":"Dumbbell_Squat_To_A_Bench","name":"Dumbbell Squat To A Bench","equipment":"dumbbell","primaryMuscles":["quadriceps"],"secondaryMuscles":["calves","glutes","hamstrings","lower back"],"instructions":["Stand up straight with a flat bench behind you while holding a dumbbell on each hand (palms facing the side of your legs).","Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.","Begin to slowly lower your torso by bending the knees as you maintain a straight posture with the head up. Continue down until you slightly touch the bench behind you. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.","Begin to raise the bar as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Dumbbell_Squat_To_A_Bench/0.jpg","Dumbbell_Squat_To_A_Bench/1.jpg"]},{"id":"Dumbbell_Step_Ups","name":"Dumbbell Step Ups","equipment":"dumbbell","primaryMuscles":["quadriceps"],"secondaryMuscles":["calves","glutes","hamstrings"],"instructions":["Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).","Place the right foot on the elevated platform. Step on the platform by extending the hip and the knee of your right leg. Use the heel mainly to lift the rest of your body up and place the foot of the left leg on the platform as well. Breathe out as you execute the force required to come up.","Step down with the left leg by flexing the hip and knee of the right leg as you inhale. Return to the original standing position by placing the right foot of to next to the left foot on the initial position.","Repeat with the right leg for the recommended amount of repetitions and then perform with the left leg."],"images":["Dumbbell_Step_Ups/0.jpg","Dumbbell_Step_Ups/1.jpg"]},{"id":"Dumbbell_Tricep_Extension_-Pronated_Grip","name":"Dumbbell Tricep Extension -Pronated Grip","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Lie down on a flat bench holding two dumbbells directly above your shoulders. Your arms should be fully extended and form a 90 degree angle from your torso and the floor.","The palms of your hands should be facing forward, and your elbows should be tucked in. This will be your starting position.","Now, inhale and slowly lower the dumbbells until they are near your ears. Be sure to keep your upper arms stationary and your elbows tucked in.","Then, exhale and use your triceps to return the weight to the starting position."],"images":["Dumbbell_Tricep_Extension_-Pronated_Grip/0.jpg","Dumbbell_Tricep_Extension_-Pronated_Grip/1.jpg"]},{"id":"Elbow_to_Knee","name":"Elbow to Knee","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie on the floor, crossing your right leg across your bent left knee. Clasp your hands behind your head, beginning with your shoulder blades on the ground. This will be your starting position.","Perform the motion by flexing the spine and rotating your torso to bring the left elbow to the right knee.","Return to the starting position and repeat the movement for the desired number of repetitions before switching sides."],"images":["Elbow_to_Knee/0.jpg","Elbow_to_Knee/1.jpg"]},{"id":"External_Rotation","name":"External Rotation","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.","Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm. Tip: Keep the arm parallel to your torso.","Now bend the elbow while keeping the upper arm stationary. In this manner, the forearm will be parallel to the floor and perpendicular to your torso (Tip: So the forearm will be directly in front of you). The upper arm will be stationary by your torso and should be parallel to the floor (aligned with your torso at all times). This will be your starting position.","As you breathe out, externally rotate your forearm so that the dumbbell is lifted up in a semicircle motion as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is perpendicular to the floor and the torso pointing towards the ceiling. At this point you will hold the contraction for a second.","As you breathe in, slowly go back to the starting position.","Repeat for the recommended amount of repetitions and then switch to the other arm."],"images":["External_Rotation/0.jpg","External_Rotation/1.jpg"]},{"id":"External_Rotation_with_Band","name":"External Rotation with Band","equipment":"bands","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Choke the band around a post. The band should be at the same height as your elbow. Stand with your left side to the band a couple of feet away.","Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.","With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching across the front of your torso. This will be your starting position.","Execute the movement by rotating your arm in a backhand motion, keeping your elbow in place.","Continue as far as you are able, pause, and then return to the starting position."],"images":["External_Rotation_with_Band/0.jpg","External_Rotation_with_Band/1.jpg"]},{"id":"Flat_Bench_Leg_Pull-In","name":"Flat Bench Leg Pull-In","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie on an exercise mat or a flat bench with your legs off the end.","Place your hands either under your glutes with your palms down or by the sides holding on to the bench (or with palms down by the side on an exercise mat). Also extend your legs straight out. This will be your starting position.","Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue this movement until your knees are near your chest. Hold the contracted position for a second.","As you breathe in, slowly return to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Flat_Bench_Leg_Pull-In/0.jpg","Flat_Bench_Leg_Pull-In/1.jpg"]},{"id":"Flat_Bench_Lying_Leg_Raise","name":"Flat Bench Lying Leg Raise","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie with your back flat on a bench and your legs extended in front of you off the end.","Place your hands either under your glutes with your palms down or by the sides holding on to the bench. This will be your starting position.","As you keep your legs extended, straight as possible with your knees slightly bent but locked raise your legs until they make a 90-degree angle with the floor. Exhale as you perform this portion of the movement and hold the contraction at the top for a second.","Now, as you inhale, slowly lower your legs back down to the starting position."],"images":["Flat_Bench_Lying_Leg_Raise/0.jpg","Flat_Bench_Lying_Leg_Raise/1.jpg"]},{"id":"Flexor_Incline_Dumbbell_Curls","name":"Flexor Incline Dumbbell Curls","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Hold the dumbbell towards the side farther from you so that you have more weight on the side closest to you. (This can be done for a good effect on all bicep dumbbell exercises). Now do a normal incline dumbbell curl, but keep your wrists as far back as possible so as to neutralize any stress that is placed on them.","Sit on an incline bench that is angled at 45-degrees while holding a dumbbell on each hand.","Let your arms hang down on your sides, with the elbows in, and turn the palms of your hands forward with the thumbs pointing away from the body. Tip: You will keep this hand position throughout the movement as there should not be any twisting of the hands as they come up. This will be your starting position.","Curl up the two dumbbells at the same time until your biceps are fully contracted and exhale. Tip: Do not swing the arms or use momentum. Keep a controlled motion at all times. Hold the contracted position for a second at the top.","As you inhale, slowly go back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Flexor_Incline_Dumbbell_Curls/0.jpg","Flexor_Incline_Dumbbell_Curls/1.jpg"]},{"id":"Flutter_Kicks","name":"Flutter Kicks","equipment":"body weight","primaryMuscles":["glutes"],"secondaryMuscles":["hamstrings"],"instructions":["On a flat bench lie facedown with the hips on the edge of the bench, the legs straight with toes high off the floor and with the arms on top of the bench holding on to the front edge.","Squeeze your glutes and hamstrings and straighten the legs until they are level with the hips. This will be your starting position.","Start the movement by lifting the left leg higher than the right leg.","Then lower the left leg as you lift the right leg.","Continue alternating in this manner (as though you are doing a flutter kick in water) until you have done the recommended amount of repetitions for each leg. Make sure that you keep a controlled movement at all times. Tip: You will breathe normally as you perform this movement."],"images":["Flutter_Kicks/0.jpg","Flutter_Kicks/1.jpg"]},{"id":"Freehand_Jump_Squat","name":"Freehand Jump Squat","equipment":"body weight","primaryMuscles":["quadriceps"],"secondaryMuscles":["calves","glutes","hamstrings"],"instructions":["Cross your arms over your chest.","With your head up and your back straight, position your feet at shoulder width.","Keeping your back straight and chest up, squat down as you inhale until your upper thighs are parallel, or lower, to the floor.","Now pressing mainly with the ball of your feet, jump straight up in the air as high as possible, using the thighs like springs. Exhale during this portion of the movement.","When you touch the floor again, immediately squat down and jump again.","Repeat for the recommended amount of repetitions."],"images":["Freehand_Jump_Squat/0.jpg","Freehand_Jump_Squat/1.jpg"]},{"id":"Frog_Sit-Ups","name":"Frog Sit-Ups","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie with your back flat on the floor (or exercise mat) and your legs extended in front of you.","Now bend at the knees and place your outer thighs by the floor (or mat) as you make the soles of your feet touch each other.","Now try pushing both soles and bringing them up as near you as possible while you keep the outer thighs on the floor (or at least almost touching it). Tip: In this position your legs should create a diamond shape.","Now, cross your arms in front of you by touching the opposite shoulders. This will be your starting position.","As you exhale flatten your lower back to the floor while curling the torso upwards. Tip: This will be like performing the first 1/4 movement of a sit up. Hold at the top position for a second.","As you inhale, slowly lower back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Frog_Sit-Ups/0.jpg","Frog_Sit-Ups/1.jpg"]},{"id":"Front_Dumbbell_Raise","name":"Front Dumbbell Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the left dumbbell to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top. Inhale after the second pause.","Now lower the dumbbell back down slowly to the starting position as you simultaneously lift the right dumbbell.","Continue alternating in this fashion until all of the recommended amount of repetitions have been performed for each arm."],"images":["Front_Dumbbell_Raise/0.jpg","Front_Dumbbell_Raise/1.jpg"]},{"id":"Front_Incline_Dumbbell_Raise","name":"Front Incline Dumbbell Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Sit down on an incline bench with the incline set anywhere between 30 to 60 degrees while holding a dumbbell on each hand. Tip: You can change the angle to hit the muscle a little differently each time.","Extend your arms straight in front of you and have your palms facing down with the dumbbells raised about 1 inch above your thighs. This will be your starting position.","Slowly raise the dumbbells straight up until they are slightly above your shoulders, while keeping your elbows locked. Squeeze at the top for a second and make sure you breathe out during this portion of the movement. Tip: Keep your head resting down against the bench and your legs on the floor at all times.","Lower the arms back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Front_Incline_Dumbbell_Raise/0.jpg","Front_Incline_Dumbbell_Raise/1.jpg"]},{"id":"Front_Two-Dumbbell_Raise","name":"Front Two-Dumbbell Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the dumbbells to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arms are slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.","As you inhale, lower the dumbbells back down slowly to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Front_Two-Dumbbell_Raise/0.jpg","Front_Two-Dumbbell_Raise/1.jpg"]},{"id":"Glute_Kickback","name":"Glute Kickback","equipment":"body weight","primaryMuscles":["glutes"],"secondaryMuscles":["hamstrings"],"instructions":["Kneel on the floor or an exercise mat and bend at the waist with your arms extended in front of you (perpendicular to the torso) in order to get into a kneeling push-up position but with the arms spaced at shoulder width. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.","As you exhale, lift up your right leg until the hamstrings are in line with the back while maintaining the 90-degree angle bend. Contract the glutes throughout this movement and hold the contraction at the top for a second. Tip: At the end of the movement the upper leg should be parallel to the floor while the calf should be perpendicular to it.","Go back to the initial position as you inhale and now repeat with the left leg.","Continue to alternate legs until all of the recommended repetitions have been performed."],"images":["Glute_Kickback/0.jpg","Glute_Kickback/1.jpg"]},{"id":"Gorilla_Chin_Crunch","name":"Gorilla Chin/Crunch","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":["biceps","lats"],"instructions":["Hang from a chin-up bar using an underhand grip (palms facing you) that is slightly wider than shoulder width.","Now bend your knees at a 90 degree angle so that the calves are parallel to the floor while the thighs remain perpendicular to it. This will be your starting position.","As you exhale, pull yourself up while crunching your knees up at the same time until your knees are at chest level. You will stop going up as soon as your nose is at the same level as the bar. Tip: When you get to this point you should also be finishing the crunch at the same time.","Slowly start to inhale as you return to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Gorilla_Chin_Crunch/0.jpg","Gorilla_Chin_Crunch/1.jpg"]},{"id":"Hammer_Curls","name":"Hammer Curls","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.","The palms of the hands should be facing your torso. This will be your starting position.","Now, while holding your upper arm stationary, exhale and curl the weight forward while contracting the biceps. Continue to raise the weight until the biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief moment as you squeeze the biceps. Tip: Focus on keeping the elbow stationary and only moving your forearm.","After the brief pause, inhale and slowly begin the lower the dumbbells back down to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Hammer_Curls/0.jpg","Hammer_Curls/1.jpg"]},{"id":"Hammer_Grip_Incline_DB_Bench_Press","name":"Hammer Grip Incline DB Bench Press","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.","Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.","Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions.","When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells."],"images":["Hammer_Grip_Incline_DB_Bench_Press/0.jpg","Hammer_Grip_Incline_DB_Bench_Press/1.jpg"]},{"id":"Handstand_Push-Ups","name":"Handstand Push-Ups","equipment":"body weight","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["With your back to the wall bend at the waist and place both hands on the floor at shoulder width.","Kick yourself up against the wall with your arms straight. Your body should be upside down with the arms and legs fully extended. Keep your whole body as straight as possible. Tip: If doing this for the first time, have a spotter help you. Also, make sure that you keep facing the wall with your head, rather than looking down.","Slowly lower yourself to the ground as you inhale until your head almost touches the floor. Tip: It is of utmost importance that you come down slow in order to avoid head injury.","Push yourself back up slowly as you exhale until your elbows are nearly locked.","Repeat for the recommended amount of repetitions."],"images":["Handstand_Push-Ups/0.jpg","Handstand_Push-Ups/1.jpg"]},{"id":"Hanging_Leg_Raise","name":"Hanging Leg Raise","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Hang from a chin-up bar with both arms extended at arms length in top of you using either a wide grip or a medium grip. The legs should be straight down with the pelvis rolled slightly backwards. This will be your starting position.","Raise your legs until the torso makes a 90-degree angle with the legs. Exhale as you perform this movement and hold the contraction for a second or so.","Go back slowly to the starting position as you breathe in.","Repeat for the recommended amount of repetitions."],"images":["Hanging_Leg_Raise/0.jpg","Hanging_Leg_Raise/1.jpg"]},{"id":"Hanging_Pike","name":"Hanging Pike","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Hang from a chin-up bar with your legs and feet together using an overhand grip (palms facing away from you) that is slightly wider than shoulder width. Tip: You may use wrist wraps in order to facilitate holding on to the bar.","Now bend your knees at a 90 degree angle and bring the upper legs forward so that the calves are perpendicular to the floor while the thighs remain parallel to it. This will be your starting position.","Pull your legs up as you exhale until you almost touch your shins with the bar above you. Tip: Try to straighten your legs as much as possible while at the top.","Lower your legs as slowly as possible until you reach the starting position. Tip: Avoid swinging and using momentum at all times.","Repeat for the recommended amount of repetitions."],"images":["Hanging_Pike/0.jpg","Hanging_Pike/1.jpg"]},{"id":"Hip_Extension_with_Bands","name":"Hip Extension with Bands","equipment":"bands","primaryMuscles":["glutes"],"secondaryMuscles":["hamstrings"],"instructions":["Secure one end of the band to the lower portion of a post and attach the other to one ankle.","Facing the attachment point of the band, hold on to the column to stabilize yourself.","Keeping your head and your chest up, move the resisted leg back as far as you can while keeping the knee straight.","Return the leg to the starting position."],"images":["Hip_Extension_with_Bands/0.jpg","Hip_Extension_with_Bands/1.jpg"]},{"id":"Hip_Flexion_with_Band","name":"Hip Flexion with Band","equipment":"bands","primaryMuscles":["quadriceps"],"secondaryMuscles":[],"instructions":["Secure one end of the band to the lower portion of a post and attach the other to one ankle.","Face away from the attachment point of the band.","Keeping your head and your chest up, raise your knee up to 90 degrees and pause.","Return the leg to the starting position."],"images":["Hip_Flexion_with_Band/0.jpg","Hip_Flexion_with_Band/1.jpg"]},{"id":"Hyperextensions_With_No_Hyperextension_Bench","name":"Hyperextensions With No Hyperextension Bench","equipment":"body weight","primaryMuscles":["lower back"],"secondaryMuscles":["glutes","hamstrings"],"instructions":["With someone holding down your legs, slide yourself down to the edge a flat bench until your hips hang off the end of the bench. Tip: Your entire upper body should be hanging down towards the floor. Also, you will be in the same position as if you were on a hyperextension bench but the range of motion will be shorter due to the height of the flat bench vs. that of the hyperextension bench.","With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.","Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you almost touch the floor or you feel a nice stretch on the hamstrings (whichever comes first). Tip: Never round the back as you perform this exercise.","Slowly raise your torso back to the initial position as you exhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.","Repeat for the recommended amount of repetitions."],"images":["Hyperextensions_With_No_Hyperextension_Bench/0.jpg","Hyperextensions_With_No_Hyperextension_Bench/1.jpg"]},{"id":"Incline_Dumbbell_Bench_With_Palms_Facing_In","name":"Incline Dumbbell Bench With Palms Facing In","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.","By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.","Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.","Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions.","When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells."],"images":["Incline_Dumbbell_Bench_With_Palms_Facing_In/0.jpg","Incline_Dumbbell_Bench_With_Palms_Facing_In/1.jpg"]},{"id":"Incline_Dumbbell_Curl","name":"Incline Dumbbell Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Sit back on an incline bench with a dumbbell in each hand held at arms length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.","While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat for the recommended amount of repetitions."],"images":["Incline_Dumbbell_Curl/0.jpg","Incline_Dumbbell_Curl/1.jpg"]},{"id":"Incline_Dumbbell_Flyes","name":"Incline Dumbbell Flyes","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders"],"instructions":["Hold a dumbbell on each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.","Extend your arms above you with a slight bend at the elbows.","Now rotate the wrists so that the palms of your hands are facing you. Tip: The pinky fingers should be next to each other. This will be your starting position.","As you breathe in, start to slowly lower the arms to the side while keeping the arms extended and while rotating the wrists until the palms of the hand are facing each other. Tip: At the end of the movement the arms will be by your side with the palms facing the ceiling.","As you exhale start to bring the dumbbells back up to the starting position by reversing the motion and rotating the hands so that the pinky fingers are next to each other again. Tip: Keep in mind that the movement will only happen at the shoulder joint and at the wrist. There is no motion that happens at the elbow joint.","Repeat for the recommended amount of repetitions."],"images":["Incline_Dumbbell_Flyes/0.jpg","Incline_Dumbbell_Flyes/1.jpg"]},{"id":"Incline_Dumbbell_Flyes_-_With_A_Twist","name":"Incline Dumbbell Flyes - With A Twist","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders"],"instructions":["Hold a dumbbell in each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.","Extend your arms above you with a slight bend at the elbows.","Now rotate the wrists so that the palms of your hands are facing you. Tip: The pinky fingers should be next to each other. This will be your starting position.","As you breathe in, start to slowly lower the arms to the side while keeping the arms extended and while rotating the wrists until the palms of the hand are facing each other. Tip: At the end of the movement the arms will be by your side with the palms facing the ceiling.","As you exhale start to bring the dumbbells back up to the starting position by reversing the motion and rotating the hands so that the pinky fingers are next to each other again. Tip: Keep in mind that the movement will only happen at the shoulder joint and at the wrist. There is no motion that happens at the elbow joint.","Repeat for the recommended amount of repetitions."],"images":["Incline_Dumbbell_Flyes_-_With_A_Twist/0.jpg","Incline_Dumbbell_Flyes_-_With_A_Twist/1.jpg"]},{"id":"Incline_Dumbbell_Press","name":"Incline Dumbbell Press","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie back on an incline bench with a dumbbell in each hand atop your thighs. The palms of your hands will be facing each other.","Then, using your thighs to help push the dumbbells up, lift the dumbbells one at a time so that you can hold them at shoulder width.","Once you have the dumbbells raised to shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","Be sure to keep full control of the dumbbells at all times. Then breathe out and push the dumbbells up with your chest.","Lock your arms at the top, hold for a second, and then start slowly lowering the weight. Tip Ideally, lowering the weights should take about twice as long as raising them.","Repeat the movement for the prescribed amount of repetitions.","When you are done, place the dumbbells back on your thighs and then on the floor. This is the safest manner to release the dumbbells."],"images":["Incline_Dumbbell_Press/0.jpg","Incline_Dumbbell_Press/1.jpg"]},{"id":"Incline_Hammer_Curls","name":"Incline Hammer Curls","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Seat yourself on an incline bench with a dumbbell in each hand. You should pressed firmly against he back with your feet together. Allow the dumbbells to hang straight down at your side, holding them with a neutral grip. This will be your starting position.","Initiate the movement by flexing at the elbow, attempting to keep the upper arm stationary.","Continue to the top of the movement and pause, then slowly return to the start position."],"images":["Incline_Hammer_Curls/0.jpg","Incline_Hammer_Curls/1.jpg"]},{"id":"Incline_Inner_Biceps_Curl","name":"Incline Inner Biceps Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Hold a dumbbell in each hand and lie back on an incline bench.","The dumbbells should be at arm's length hanging at your sides and your palms should be facing out. This will be your starting position.","Now as you exhale curl the weight outward and up while keeping your forearms in line with your side deltoids. Continue the curl until the dumbbells are at shoulder height and to the sides of your deltoids. Tip: The end of the movement should look similar to a double biceps pose.","After a second contraction at the top of the movement, start to inhale and slowly lower the weights back to the starting position using the same path used to bring them up.","Repeat for the recommended amount of repetitions."],"images":["Incline_Inner_Biceps_Curl/0.jpg","Incline_Inner_Biceps_Curl/1.jpg"]},{"id":"Incline_Push-Up","name":"Incline Push-Up","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Stand facing bench or sturdy elevated platform. Place hands on edge of bench or platform, slightly wider than shoulder width.","Position forefoot back from bench or platform with arms and body straight. Arms should be perpendicular to body. Keeping body straight, lower chest to edge of box or platform by bending arms.","Push body up until arms are extended. Repeat."],"images":["Incline_Push-Up/0.jpg","Incline_Push-Up/1.jpg"]},{"id":"Incline_Push-Up_Close-Grip","name":"Incline Push-Up Close-Grip","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands next to one another on the bar.","Position your feet back from the bar with arms and body straight. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],"images":["Incline_Push-Up_Close-Grip/0.jpg","Incline_Push-Up_Close-Grip/1.jpg"]},{"id":"Incline_Push-Up_Medium","name":"Incline Push-Up Medium","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["abdominals","shoulders","triceps"],"instructions":["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands on the bar, with your hands about shoulder width apart.","Position your feet back from the bar with arms and body straight. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],"images":["Incline_Push-Up_Medium/0.jpg","Incline_Push-Up_Medium/1.jpg"]},{"id":"Incline_Push-Up_Reverse_Grip","name":"Incline Push-Up Reverse Grip","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["abdominals","shoulders","triceps"],"instructions":["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands on the bar palms up, with your hands about shoulder width apart.","Position your feet back from the bar with arms and body straight. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],"images":["Incline_Push-Up_Reverse_Grip/0.jpg","Incline_Push-Up_Reverse_Grip/1.jpg"]},{"id":"Incline_Push-Up_Wide","name":"Incline Push-Up Wide","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["abdominals","shoulders","triceps"],"instructions":["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.","Place your hands on the bar, with your hands wider than shoulder width.","Position your feet back from the bar with arms and body straight. Your arms should be perpendicular to the body. This will be your starting position.","Keeping your body straight, lower your chest to the bar by bending the arms.","Return to the starting position by extending the elbows, pressing yourself back up."],"images":["Incline_Push-Up_Wide/0.jpg","Incline_Push-Up_Wide/1.jpg"]},{"id":"Internal_Rotation_with_Band","name":"Internal Rotation with Band","equipment":"bands","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away.","Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.","With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching away from your torso. This will be your starting position.","Execute the movement by rotating your arm in a forehand motion, keeping your elbow in place.","Continue as far as you are able, pause, and then return to the starting position."],"images":["Internal_Rotation_with_Band/0.jpg","Internal_Rotation_with_Band/1.jpg"]},{"id":"Iron_Cross","name":"Iron Cross","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["chest","glutes","hamstrings","lower back","quadriceps","traps"],"instructions":[],"images":["Iron_Cross/0.jpg","Iron_Cross/1.jpg"]},{"id":"Isometric_Neck_Exercise_-_Front_And_Back","name":"Isometric Neck Exercise - Front And Back","equipment":"body weight","primaryMuscles":["neck"],"secondaryMuscles":[],"instructions":["With your head and neck in a neutral position (normal position with head erect facing forward), place both of your hands on the front side of your head.","Now gently push forward as you contract the neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.","Hold for the recommended number of seconds.","Now release the tension slowly.","Rest for the recommended amount of time and repeat with your hands placed on the back side of your head."],"images":["Isometric_Neck_Exercise_-_Front_And_Back/0.jpg","Isometric_Neck_Exercise_-_Front_And_Back/1.jpg"]},{"id":"Isometric_Neck_Exercise_-_Sides","name":"Isometric Neck Exercise - Sides","equipment":"body weight","primaryMuscles":["neck"],"secondaryMuscles":[],"instructions":["With your head and neck in a neutral position (normal position with head erect facing forward), place your left hand on the left side of your head.","Now gently push towards the left as you contract the left neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.","Hold for the recommended number of seconds.","Now release the tension slowly.","Rest for the recommended amount of time and repeat with your right hand placed on the right side of your head."],"images":["Isometric_Neck_Exercise_-_Sides/0.jpg","Isometric_Neck_Exercise_-_Sides/1.jpg"]},{"id":"Isometric_Wipers","name":"Isometric Wipers","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["abdominals","shoulders","triceps"],"instructions":["Assume a push-up position, supporting your weight on your hands and toes while keeping your body straight. Your hands should be just outside of shoulder width. This will be your starting position.","Begin by shifting your body weight as far to one side as possible, allowing the elbow on that side to flex as you lower your body.","Reverse the motion by extending the flexed arm, pushing yourself up and then dropping to the other side.","Repeat for the desired number of repetitions."],"images":["Isometric_Wipers/0.jpg","Isometric_Wipers/1.jpg"]},{"id":"Jackknife_Sit-Up","name":"Jackknife Sit-Up","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie flat on the floor (or exercise mat) on your back with your arms extended straight back behind your head and your legs extended also. This will be your starting position.","As you exhale, bend at the waist while simultaneously raising your legs and arms to meet in a jackknife position. Tip: The legs should be extended and lifted at approximately a 35-45 degree angle from the floor and the arms should be extended and parallel to your legs. The upper torso should be off the floor.","While inhaling, lower your arms and legs back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Jackknife_Sit-Up/0.jpg","Jackknife_Sit-Up/1.jpg"]},{"id":"Janda_Sit-Up","name":"Janda Sit-Up","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Position your body on the floor in the basic sit-up position; knees to a ninety degree angle with feet flat on the floor and arms either crossed over your chest or to the sides. This will be your starting position.","As you strongly tighten your glutes and hamstrings, fill your lungs with air and in a slow (three to six second count) ascent, slowly exhale. Tip: It is important to tighten the glutes and hamstrings as this will cause the hip flexors to be inactivated in a process called reciprocal inhibition, which basically means that opposite muscles to the contracted ones will relax.","As you inhale, slowly go back in a controlled manner to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Janda_Sit-Up/0.jpg","Janda_Sit-Up/1.jpg"]},{"id":"Lateral_Raise_-_With_Bands","name":"Lateral Raise - With Bands","equipment":"bands","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["To begin, stand on an exercise band so that tension begins at arm's length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on the sides of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.","Use your side shoulders to lift the handles to the sides as you exhale. Continue to lift the handles until they are slightly above parallel. Tip: As you lift the handles, slightly tilt the hand as if you were pouring water and keep your arms extended. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the handles back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],"images":["Lateral_Raise_-_With_Bands/0.jpg","Lateral_Raise_-_With_Bands/1.jpg"]},{"id":"Leg_Lift","name":"Leg Lift","equipment":"body weight","primaryMuscles":["glutes"],"secondaryMuscles":["hamstrings"],"instructions":["While standing up straight with both feet next to each other at around shoulder width, grab a sturdy surface such as the sides of a squat rack or the top of a chair to brace yourself and keep balance.","With or without an ankle weight, lift one leg behind you as if performing a leg curl but standing up while keeping the other leg straight. Breathe out as you perform this movement.","Slowly bring the raised leg back to the floor as you breathe in.","Repeat for the recommended amount of repetitions.","Repeat the movement with the opposite leg."],"images":["Leg_Lift/0.jpg","Leg_Lift/1.jpg"]},{"id":"Leg_Pull-In","name":"Leg Pull-In","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie on an exercise mat with your legs extended and your hands either palms facing down next to you or under your glutes. Tip: My preference is with the hands next to me. This will be your starting position.","Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue the motion until your knees are around chest level. Contract your abs as you execute this movement and hold for a second at the top. Tip: As you perform the motion, the lower legs (calves) should always remain parallel to the floor.","Return to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Leg_Pull-In/0.jpg","Leg_Pull-In/1.jpg"]},{"id":"Lying_Dumbbell_Tricep_Extension","name":"Lying Dumbbell Tricep Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["Lie on a flat bench while holding two dumbbells directly in front of you. Your arms should be fully extended at a 90-degree angle from your torso and the floor. The palms should be facing in and the elbows should be tucked in. This is the starting position.","As you breathe in and you keep the upper arms stationary with the elbows in, slowly lower the weight until the dumbbells are near your ears.","At that point, while keeping the elbows in and the upper arms stationary, use the triceps to bring the weight back up to the starting position as you breathe out.","Repeat for the recommended amount of repetitions."],"images":["Lying_Dumbbell_Tricep_Extension/0.jpg","Lying_Dumbbell_Tricep_Extension/1.jpg"]},{"id":"Lying_One-Arm_Lateral_Raise","name":"Lying One-Arm Lateral Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["While holding a dumbbell in one hand, lay with your chest down on a flat bench. The other hand can be used to hold to the leg of the bench for stability.","Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.","Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbell to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Lying_One-Arm_Lateral_Raise/0.jpg","Lying_One-Arm_Lateral_Raise/1.jpg"]},{"id":"Lying_Rear_Delt_Raise","name":"Lying Rear Delt Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["While holding a dumbbell in each hand, lay with your chest down on a flat bench.","Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.","Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.","Slowly lower the dumbbells to the starting position as you inhale.","Repeat for the recommended amount of repetitions and then switch to the other arm."],"images":["Lying_Rear_Delt_Raise/0.jpg","Lying_Rear_Delt_Raise/1.jpg"]},{"id":"Lying_Supine_Dumbbell_Curl","name":"Lying Supine Dumbbell Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Lie down on a flat bench face up while holding a dumbbell in each arm on top of your thighs.","Bring the dumbbells to the sides with the arms extended and the palms of the hands facing your thighs (neutral grip).","While keeping the arms close to your torso and elbows in, slowly lower your arms (as you keep them extended with a slight bend at the elbows) as far down towards the floor as you can go. Once you cannot go down any further, lock your upper arms in that position and that will be your starting position.","As you breathe out, slowly begin to curl the weights up as you simultaneously rotate your wrists so that the palms of the hands face up. Continue curling the weight until your biceps are fully contracted and squeeze hard at the top position for a second. Tip: Only the forearms should move. Upper arms should remain stationary and elbows should stay in throughout the movement.","Return back to the starting position very slowly."],"images":["Lying_Supine_Dumbbell_Curl/0.jpg","Lying_Supine_Dumbbell_Curl/1.jpg"]},{"id":"Middle_Back_Shrug","name":"Middle Back Shrug","equipment":"dumbbell","primaryMuscles":["middle back"],"secondaryMuscles":[],"instructions":["Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position.","As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms.","As you inhale go back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Middle_Back_Shrug/0.jpg","Middle_Back_Shrug/1.jpg"]},{"id":"Monster_Walk","name":"Monster Walk","equipment":"bands","primaryMuscles":["abductors"],"secondaryMuscles":[],"instructions":["Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart.","To begin, take short steps forward alternating your left and right foot.","After several steps, do just the opposite and walk backward to where you started."],"images":["Monster_Walk/0.jpg","Monster_Walk/1.jpg"]},{"id":"Natural_Glute_Ham_Raise","name":"Natural Glute Ham Raise","equipment":"body weight","primaryMuscles":["hamstrings"],"secondaryMuscles":["calves","glutes","lower back"],"instructions":["Using the leg pad of a lat pulldown machine or a preacher bench, position yourself so that your ankles are under the pads, knees on the seat, and you are facing away from the machine. You should be upright and maintaining good posture.","This will be your starting position. Lower yourself under control until your knees are almost completely straight.","Remaining in control, raise yourself back up to the starting position.","If you are unable to complete a rep, use a band, a partner, or push off of a box to aid in completing a repetition."],"images":["Natural_Glute_Ham_Raise/0.jpg","Natural_Glute_Ham_Raise/1.jpg"]},{"id":"Oblique_Crunches","name":"Oblique Crunches","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put one hand beside your head and the other to the side against the floor.","Make sure your feet are elevated and resting on a flat surface.","Now lift the shoulder in which your hand is touching your head.","Simply elevate your shoulder and body upward until you touch your knee. For example, if you have your right hand besides your head, then you want to elevate your body upwards until your right elbow touches your left knee. The same variation can be applied doing the inverse and using your left elbow to touch your right knee.","After your knee touches your elbow, lower your body until you have reached the starting position.","Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (upward) part of the exercise.","Continue alternating in this manner until all of the recommended repetitions for each side have been completed."],"images":["Oblique_Crunches/0.jpg","Oblique_Crunches/1.jpg"]},{"id":"Oblique_Crunches_-_On_The_Floor","name":"Oblique Crunches - On The Floor","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Start out by lying on your right side with your legs lying on top of each other. Make sure your knees are bent a little bit.","Place your left hand behind your head.","Once you are in this set position, begin by moving your left elbow up as you would perform a normal crunch except this time the main emphasis is on your obliques.","Crunch as high as you can, hold the contraction for a second and then slowly drop back down into the starting position.","Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (elevation) part of the exercise."],"images":["Oblique_Crunches_-_On_The_Floor/0.jpg","Oblique_Crunches_-_On_The_Floor/1.jpg"]},{"id":"One_Arm_Dumbbell_Bench_Press","name":"One Arm Dumbbell Bench Press","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie down on a flat bench with a dumbbell in one hand on top of your thigh.","By using your thigh to help you get the dumbbell up, clean the dumbbell up so that you can hold it in front of you at shoulder width. Use the hand you are not lifting with to help position the dumbbell over you properly.","Once at shoulder width, rotate your wrist forward so that the palm of your hand is facing away from you. This will be your starting position.","Bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbell at all times. Tip: Use the hand that you are not lifting with to help keep the dumbbell balance as you may struggle a bit at first. Only use your non-lifting hand if it is needed. Otherwise, keep it resting to the side.","As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions of your training program.","Switch arms and repeat the movement."],"images":["One_Arm_Dumbbell_Bench_Press/0.jpg","One_Arm_Dumbbell_Bench_Press/1.jpg"]},{"id":"One_Arm_Dumbbell_Preacher_Curl","name":"One Arm Dumbbell Preacher Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Grab a dumbbell with the right arm and place the upper arm on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.","As you breathe in, slowly lower the dumbbell until your upper arm is extended and the biceps is fully stretched.","As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbell is at shoulder height. Again, remember that to ensure full contraction you need to bring that small finger higher than the thumb.","Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions.","Switch arms and repeat the movement."],"images":["One_Arm_Dumbbell_Preacher_Curl/0.jpg","One_Arm_Dumbbell_Preacher_Curl/1.jpg"]},{"id":"One_Arm_Pronated_Dumbbell_Triceps_Extension","name":"One Arm Pronated Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your feet as a pronated grip is required to perform this exercise.","Place your non lifting hand on your bicep for support.","Slowly begin to lower the dumbbell down as you breathe in.","Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).","Repeat until you have performed your set repetitions.","Switch arms and repeat the movement."],"images":["One_Arm_Pronated_Dumbbell_Triceps_Extension/0.jpg","One_Arm_Pronated_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"One_Arm_Supinated_Dumbbell_Triceps_Extension","name":"One Arm Supinated Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your face as a supinated grip is required to perform this exercise.","Place your non lifting hand on your bicep for support.","Slowly begin to lower the dumbbell down as you breathe in.","Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).","Repeat until you have performed your set repetitions.","Switch arms and repeat the movement.","Switch arms again and repeat the movement."],"images":["One_Arm_Supinated_Dumbbell_Triceps_Extension/0.jpg","One_Arm_Supinated_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"One-Arm_Dumbbell_Row","name":"One-Arm Dumbbell Row","equipment":"dumbbell","primaryMuscles":["middle back"],"secondaryMuscles":["biceps","lats","shoulders"],"instructions":["Choose a flat bench and place a dumbbell on each side of it.","Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support.","Use the left hand to pick up the dumbbell on the floor and hold the weight while keeping your lower back straight. The palm of the hand should be facing your torso. This will be your starting position.","Pull the resistance straight up to the side of your chest, keeping your upper arm close to your side and keeping the torso stationary. Breathe out as you perform this step. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. Also, make sure that the force is performed with the back muscles and not the arms. Finally, the upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the dumbbell; therefore do not try to pull the dumbbell up using the forearms.","Lower the resistance straight down to the starting position. Breathe in as you perform this step.","Repeat the movement for the specified amount of repetitions.","Switch sides and repeat again with the other arm."],"images":["One-Arm_Dumbbell_Row/0.jpg","One-Arm_Dumbbell_Row/1.jpg"]},{"id":"One-Arm_Flat_Bench_Dumbbell_Flye","name":"One-Arm Flat Bench Dumbbell Flye","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":[],"instructions":["Lie down on a flat bench with a dumbbell in one hand resting on top of your thigh. The palm of your hand with the dumbbell in it should be at a neutral grip.","By using your thighs to help you get the dumbbell up, clean the dumbbell so that you can hold it in front of you with your lifting arm being fully extended. Remember to maintain a neutral grip with this exercise. Your non lifting hand should be to the side holding the flat bench for better support. This will be your starting position.","Your arm with the weight should have a slight bend on your elbow in order to prevent stress at the biceps tendon. Begin by lowering your arm with the weight in it out in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, your lifting arm should remain stationary; the movement should only occur at the shoulder joint.","Return your lifting arm back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.","Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the exercise."],"images":["One-Arm_Flat_Bench_Dumbbell_Flye/0.jpg","One-Arm_Flat_Bench_Dumbbell_Flye/1.jpg"]},{"id":"One-Arm_Incline_Lateral_Raise","name":"One-Arm Incline Lateral Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Lie down sideways on an incline bench press with a dumbbell in the hand. Make sure the shoulder is pressing against the incline bench and the arm is lying across your body with the palm around your navel.","Hold a dumbbell in your uppermost arm while keeping it extended in front of you parallel to the floor. This is your starting position.","While keeping the dumbbell parallel to the floor at all times, perform a lateral raise. Your arm should travel straight up until it is pointing at the ceiling. Tip: Exhale as you perform this movement. Hold the dumbbell in the position and feel the contraction in the shoulders for a second.","While inhaling lower the weight across your body back into the starting position.","Repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the movement."],"images":["One-Arm_Incline_Lateral_Raise/0.jpg","One-Arm_Incline_Lateral_Raise/1.jpg"]},{"id":"One-Arm_Side_Laterals","name":"One-Arm Side Laterals","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Pick a dumbbell and place it in one of your hands. Your non lifting hand should be used to grab something steady such as an incline bench press. Lean towards your lifting arm and away from the hand that is gripping the incline bench as this will allow you to keep your balance.","Stand with a straight torso and have the dumbbell by your side at arm's length with the palm of the hand facing you. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the dumbbell to your side with a slight bend on the elbow and your hand slightly tilted forward as if pouring water in a glass. Continue to go up until you arm is parallel to the floor. Exhale as you execute this movement and pause for a second at the top.","Lower the dumbbell back down slowly to the starting position as you inhale.","Repeat for the recommended amount of repetitions.","Switch arms and repeat the exercise."],"images":["One-Arm_Side_Laterals/0.jpg","One-Arm_Side_Laterals/1.jpg"]},{"id":"Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench","name":"Palms-Down Dumbbell Wrist Curl Over A Bench","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Start out by placing two dumbbells on one side of a flat bench.","Kneel down on both of your knees so that your body is facing the flat bench.","Use your arms to grab both of the dumbbells with a pronated grip (palms facing down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling.","Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions."],"images":["Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg","Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/1.jpg"]},{"id":"Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench","name":"Palms-Up Dumbbell Wrist Curl Over A Bench","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Start out by placing two dumbbells on one side of a flat bench.","Kneel down on both of your knees so that your body is facing the flat bench.","Use your arms to grab both of the dumbbells with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise.","Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions."],"images":["Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg","Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/1.jpg"]},{"id":"Plank","name":"Plank","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.","Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised."],"images":["Plank/0.jpg","Plank/1.jpg"]},{"id":"Plie_Dumbbell_Squat","name":"Plie Dumbbell Squat","equipment":"dumbbell","primaryMuscles":["quadriceps"],"secondaryMuscles":["abdominals","calves","glutes","hamstrings"],"instructions":["Hold a dumbbell at the base with both hands and stand straight up. Move your legs so that they are wider than shoulder width apart from each other with your knees slightly bent.","Your toes should be facing out. Note: Your arms should be stationary while performing the exercise. This is the starting position.","Slowly bend the knees and lower your legs until your thighs are parallel to the floor. Make sure to inhale as this is the eccentric part of the exercise.","Press mainly with the heel of the foot to bring the body back to the starting position while exhaling.","Repeat for the recommended amount of repetitions."],"images":["Plie_Dumbbell_Squat/0.jpg","Plie_Dumbbell_Squat/1.jpg"]},{"id":"Power_Partials","name":"Power Partials","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.","The palms of the hands should be facing your torso. Your feet should be about shoulder width apart. This will be your starting position.","Keeping your arms straight and the torso stationary, lift the weights out to your sides until they are about shoulder level height while exhaling.","Feel the contraction for a second and begin to lower the weights back down to the starting position while inhaling. Tip: Keep the palms facing down with the little finger slightly higher while lifting and lowering the weights as it will concentrate the stress on your shoulders mainly.","Repeat for the recommended amount of repetitions."],"images":["Power_Partials/0.jpg","Power_Partials/1.jpg"]},{"id":"Preacher_Hammer_Dumbbell_Curl","name":"Preacher Hammer Dumbbell Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Place the upper part of both arms on top of the preacher bench as you hold a dumbbell in each hand with the palms facing each other (neutral grip).","As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.","As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbells are at shoulder height.","Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions."],"images":["Preacher_Hammer_Dumbbell_Curl/0.jpg","Preacher_Hammer_Dumbbell_Curl/1.jpg"]},{"id":"Pullups","name":"Pullups","equipment":"body weight","primaryMuscles":["lats"],"secondaryMuscles":["biceps","middle back"],"instructions":["Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.","As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.","Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.","After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.","Repeat this motion for the prescribed amount of repetitions."],"images":["Pullups/0.jpg","Pullups/1.jpg"]},{"id":"Push_Up_to_Side_Plank","name":"Push Up to Side Plank","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["abdominals","shoulders","triceps"],"instructions":["Get into pushup position on the toes with your hands just outside of shoulder width.","Perform a pushup by allowing the elbows to flex. As you descend, keep your body straight.","Do one pushup and as you come up, shift your weight on the left side of the body, twist to the side while bringing the right arm up towards the ceiling in a side plank.","Lower the arm back to the floor for another pushup and then twist to the other side.","Repeat the series, alternating each side, for 10 or more reps."],"images":["Push_Up_to_Side_Plank/0.jpg","Push_Up_to_Side_Plank/1.jpg"]},{"id":"Push-Up_Wide","name":"Push-Up Wide","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["abdominals","shoulders","triceps"],"instructions":["With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position.","To begin, allow the elbows to flex, lowering your chest to the floor as you inhale.","Using your pectoral muscles, press your upper body back up to the starting position by extending the elbows. Exhale as you perform this step.","After pausing at the contracted position, repeat the movement for the prescribed amount of repetitions."],"images":["Push-Up_Wide/0.jpg","Push-Up_Wide/1.jpg"]},{"id":"Push-Ups_-_Close_Triceps_Position","name":"Push-Ups - Close Triceps Position","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms' length.","Lower yourself until your chest almost touches the floor as you inhale.","Using your triceps and some of your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],"images":["Push-Ups_-_Close_Triceps_Position/0.jpg","Push-Ups_-_Close_Triceps_Position/1.jpg"]},{"id":"Push-Ups_With_Feet_Elevated","name":"Push-Ups With Feet Elevated","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.","Place your toes on top of a flat bench. This will allow your body to be elevated. Note: The higher the elevation of the flat bench, the higher the resistance of the exercise is.","Lower yourself until your chest almost touches the floor as you inhale.","Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],"images":["Push-Ups_With_Feet_Elevated/0.jpg","Push-Ups_With_Feet_Elevated/1.jpg"]},{"id":"Pushups","name":"Pushups","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length.","Next, lower yourself downward until your chest almost touches the floor as you inhale.","Now breathe out and press your upper body back up to the starting position while squeezing your chest.","After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed."],"images":["Pushups/0.jpg","Pushups/1.jpg"]},{"id":"Pushups_Close_and_Wide_Hand_Positions","name":"Pushups (Close and Wide Hand Positions)","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Lie on the floor face down and body straight with your toes on the floor and the hands wider than shoulder width for a wide hand position and closer than shoulder width for a close hand position. Make sure you are holding your torso up at arms length.","Lower yourself until your chest almost touches the floor as you inhale.","Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],"images":["Pushups_Close_and_Wide_Hand_Positions/0.jpg","Pushups_Close_and_Wide_Hand_Positions/1.jpg"]},{"id":"Reverse_Crunch","name":"Reverse Crunch","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie down on the floor with your legs fully extended and arms to the side of your torso with the palms on the floor. Your arms should be stationary for the entire exercise.","Move your legs up so that your thighs are perpendicular to the floor and feet are together and parallel to the floor. This is the starting position.","While inhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the floor. At the end of this movement your knees will be touching your chest.","Hold the contraction for a second and move your legs back to the starting position while exhaling.","Repeat for the recommended amount of repetitions."],"images":["Reverse_Crunch/0.jpg","Reverse_Crunch/1.jpg"]},{"id":"Reverse_Flyes","name":"Reverse Flyes","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["To begin, lie down on an incline bench with the chest and stomach pressing against the incline. Have the dumbbells in each hand with the palms facing each other (neutral grip).","Extend the arms in front of you so that they are perpendicular to the angle of the bench. The legs should be stationary while applying pressure with the ball of your toes. This is the starting position.","Maintaining the slight bend of the elbows, move the weights out and away from each other (to the side) in an arc motion while exhaling. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.","The arms should be elevated until they are parallel to the floor.","Feel the contraction and slowly lower the weights back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],"images":["Reverse_Flyes/0.jpg","Reverse_Flyes/1.jpg"]},{"id":"Reverse_Flyes_With_External_Rotation","name":"Reverse Flyes With External Rotation","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["To begin, lie down on an incline bench set at a 30-degree angle with the chest and stomach pressing against the incline.","Have the dumbbells in each hand with the palms facing down to the floor. Your arms should be in front of you so that they are perpendicular to the angle of the bench. Tip: Your elbows should have a slight bend. The legs should be stationary while applying pressure with the ball of your toes (your heels should not be touching the floor). This is the starting position.","Maintaining the slight bend of the elbows, move the weights out and away from each other in an arc motion while exhaling.","As you lift the weight, your wrist should externally rotate by 90-degrees so that you go from a palms down (pronated) grip to a palms facing each other (neutral) grip. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.","The arms should be elevated until they are level with the head.","Feel the contraction and slowly lower the weights back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],"images":["Reverse_Flyes_With_External_Rotation/0.jpg","Reverse_Flyes_With_External_Rotation/1.jpg"]},{"id":"Russian_Twist","name":"Russian Twist","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":["lower back"],"instructions":["Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.","Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position.","Twist your torso to the right side until your arms are parallel with the floor while breathing out.","Hold the contraction for a second and move back to the starting position while breathing out. Now move to the opposite side performing the same techniques you applied to the right side.","Repeat for the recommended amount of repetitions."],"images":["Russian_Twist/0.jpg","Russian_Twist/1.jpg"]},{"id":"Seated_Bent-Over_One-Arm_Dumbbell_Triceps_Extension","name":"Seated Bent-Over One-Arm Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Sit down at the end of a flat bench with a dumbbell in one arm using a neutral grip (palms of the hand facing you).","Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.","The upper arm with the dumbbell should be close to the torso and aligned with it (lifted up until it is parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.","Keeping the upper arm stationary, use the triceps to lift the weight as you exhale until the forearm is parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the exercise."],"images":["Seated_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/0.jpg","Seated_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"Seated_Bent-Over_Rear_Delt_Raise","name":"Seated Bent-Over Rear Delt Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Place a couple of dumbbells looking forward in front of a flat bench.","Sit on the end of the bench with your legs together and the dumbbells behind your calves.","Bend at the waist while keeping the back straight in order to pick up the dumbbells. The palms of your hands should be facing each other as you pick them. This will be your starting position.","Keeping your torso forward and stationary, and the arms slightly bent at the elbows, lift the dumbbells straight to the side until both arms are parallel to the floor. Exhale as you lift the weights. (Note: avoid swinging the torso or bringing the arms back as opposed to the side.)","After a one second contraction at the top, slowly lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"images":["Seated_Bent-Over_Rear_Delt_Raise/0.jpg","Seated_Bent-Over_Rear_Delt_Raise/1.jpg"]},{"id":"Seated_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension","name":"Seated Bent-Over Two-Arm Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Sit down at the end of a flat bench with a dumbbell in both arms using a neutral grip (palms of the hand facing you).","Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.","The upper arms with the dumbbells should be close to the torso and aligned with it (lifted up until they are parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.","Keeping the upper arms stationary, use the triceps to lift the weight as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbells back to the starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions."],"images":["Seated_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/0.jpg","Seated_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"Seated_Dumbbell_Curl","name":"Seated Dumbbell Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Sit on a flat bench with a dumbbell on each hand being held at arms length. The elbows should be close to the torso.","Rotate the palms of the hands so that they are facing your torso. This will be your starting position.","While holding the upper arm stationary, curl the weights and start twisting the wrists once the dumbbells pass your thighs so that the palms of your hands face forward at the end of the movement. Make sure that you contract the biceps as you breathe out and make sure that only the forearms move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in and as you rotate the wrists back to a neutral grip.","Repeat for the recommended amount of repetitions."],"images":["Seated_Dumbbell_Curl/0.jpg","Seated_Dumbbell_Curl/1.jpg"]},{"id":"Seated_Dumbbell_Inner_Biceps_Curl","name":"Seated Dumbbell Inner Biceps Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Sit on the end of a flat bench with a dumbbell in each hand being held at arms length. The elbows should be close to the torso.","Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.","While holding the upper arms stationary, curl the dumbbells out and up, turning the palms out as you lift and keeping your forearms in line with your outer deltoids. Tips:","Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate your arms as you lower the dumbbells so that you can switch back to a neutral grip.","Repeat for the recommended amount of repetitions."],"images":["Seated_Dumbbell_Inner_Biceps_Curl/0.jpg","Seated_Dumbbell_Inner_Biceps_Curl/1.jpg"]},{"id":"Seated_Dumbbell_Palms-Down_Wrist_Curl","name":"Seated Dumbbell Palms-Down Wrist Curl","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Start out by placing two dumbbells on the floor in front of a flat bench.","Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.","Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing down. Your wrists should be hanging over the edge of your thighs.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions.","When finished, simply lower the dumbbells to the floor."],"images":["Seated_Dumbbell_Palms-Down_Wrist_Curl/0.jpg","Seated_Dumbbell_Palms-Down_Wrist_Curl/1.jpg"]},{"id":"Seated_Dumbbell_Palms-Up_Wrist_Curl","name":"Seated Dumbbell Palms-Up Wrist Curl","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Start out by placing two dumbbells on the floor in front of a flat bench.","Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.","Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing up. Your wrists should be hanging over the edge of your thighs.","Start out by curling your wrist upwards and exhaling.","Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.","Repeat for the recommended amount of repetitions.","When finished, simply lower the dumbbells to the floor."],"images":["Seated_Dumbbell_Palms-Up_Wrist_Curl/0.jpg","Seated_Dumbbell_Palms-Up_Wrist_Curl/1.jpg"]},{"id":"Seated_Dumbbell_Press","name":"Seated Dumbbell Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Grab a couple of dumbbells and sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs.","Clean the dumbbells up one at a time by using your thighs to bring the dumbbells up to shoulder height at each side.","Rotate the wrists so that the palms of your hands are facing forward. This is your starting position.","As you exhale, push the dumbbells up until they touch at the top.","After a second pause, slowly come down back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Seated_Dumbbell_Press/0.jpg","Seated_Dumbbell_Press/1.jpg"]},{"id":"Seated_Flat_Bench_Leg_Pull-In","name":"Seated Flat Bench Leg Pull-In","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.","Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.","After a second pause, go back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Seated_Flat_Bench_Leg_Pull-In/0.jpg","Seated_Flat_Bench_Leg_Pull-In/1.jpg"]},{"id":"Seated_Leg_Tucks","name":"Seated Leg Tucks","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.","Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.","After a second pause, go back to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Seated_Leg_Tucks/0.jpg","Seated_Leg_Tucks/1.jpg"]},{"id":"Seated_One-Arm_Dumbbell_Palms-Down_Wrist_Curl","name":"Seated One-Arm Dumbbell Palms-Down Wrist Curl","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Sit on a flat bench with a dumbbell in your right hand.","Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.","Lean forward and place your right forearm on top of your upper right thigh with your palm down. Tip: Make sure that the back of the wrist lies on top of your knees. This will be your starting position.","Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.","Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.","Perform for the recommended amount of repetitions, switch arms and repeat the movement."],"images":["Seated_One-Arm_Dumbbell_Palms-Down_Wrist_Curl/0.jpg","Seated_One-Arm_Dumbbell_Palms-Down_Wrist_Curl/1.jpg"]},{"id":"Seated_One-Arm_Dumbbell_Palms-Up_Wrist_Curl","name":"Seated One-Arm Dumbbell Palms-Up Wrist Curl","equipment":"dumbbell","primaryMuscles":["forearms"],"secondaryMuscles":[],"instructions":["Sit on a flat bench with a dumbbell in your right hand.","Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.","Lean forward and place your right forearm on top of your upper right thigh with your palm up. Tip: Make sure that the front of the wrist lies on top of your knees. This will be your starting position.","Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.","Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.","Perform for the recommended amount of repetitions, switch arms and repeat the movement."],"images":["Seated_One-Arm_Dumbbell_Palms-Up_Wrist_Curl/0.jpg","Seated_One-Arm_Dumbbell_Palms-Up_Wrist_Curl/1.jpg"]},{"id":"Seated_Side_Lateral_Raise","name":"Seated Side Lateral Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Pick a couple of dumbbells and sit at the end of a flat bench with your feet firmly on the floor. Hold the dumbbells with your palms facing in and your arms straight down at your sides at arms' length. This will be your starting position.","While maintaining the torso stationary (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.","Lower the dumbbells back down slowly to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Seated_Side_Lateral_Raise/0.jpg","Seated_Side_Lateral_Raise/1.jpg"]},{"id":"Seated_Triceps_Press","name":"Seated Triceps Press","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Sit down on a bench with back support and grasp a dumbbell with both hands and hold it overhead at arm's length. Tip: a better way is to have somebody hand it to you especially if it is very heavy. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hand should be facing inward. This will be your starting position.","Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semi-circular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions."],"images":["Seated_Triceps_Press/0.jpg","Seated_Triceps_Press/1.jpg"]},{"id":"See-Saw_Press_Alternating_Side_Press","name":"See-Saw Press (Alternating Side Press)","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["abdominals","triceps"],"instructions":["Grab a dumbbell with each hand and stand up erect.","Clean (lift) the dumbbells to the chest/shoulder level and then rotate your wrists so that your palms are facing towards you as if you were getting ready to perform an Arnold Press. This will be your starting position.","Now start extending your left arm overhead as you rotate the wrist so that the palm of your hand faces forward as you go up. Your elbows should come out also as you lift the weight. Simultaneously, you will also be bending from your hip to your opposite side. Tip: If you perform the exercise correctly, is should look as if you are trying to reach for something overhead on the right hand side of your body, but with your left arm. Breathe out as you perform this movement.","Once you reach the top position breathe in. Then, with the weight fully extended overhead and you bent over to your right hand side, begin the movement to the left side.","Repeat for the recommended amount of repetitions."],"images":["See-Saw_Press_Alternating_Side_Press/0.jpg","See-Saw_Press_Alternating_Side_Press/1.jpg"]},{"id":"Shoulder_Press_-_With_Bands","name":"Shoulder Press - With Bands","equipment":"bands","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["To begin, stand on an exercise band so that tension begins at arm's length. Grasp the handles and lift them so that the hands are at shoulder height at each side.","Rotate the wrists so that the palms of your hands are facing forward. Your elbows should be bent, with the upper arms and forearms in line to the torso. This is your starting position.","As you exhale, lift the handles up until your arms are fully extended overhead."],"images":["Shoulder_Press_-_With_Bands/0.jpg","Shoulder_Press_-_With_Bands/1.jpg"]},{"id":"Side_Bridge","name":"Side Bridge","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":["shoulders"],"instructions":[],"images":["Side_Bridge/0.jpg","Side_Bridge/1.jpg"]},{"id":"Side_Jackknife","name":"Side Jackknife","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":[],"images":["Side_Jackknife/0.jpg","Side_Jackknife/1.jpg"]},{"id":"Side_Lateral_Raise","name":"Side Lateral Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position.","While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.","Lower the dumbbells back down slowly to the starting position as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Side_Lateral_Raise/0.jpg","Side_Lateral_Raise/1.jpg"]},{"id":"Side_Laterals_to_Front_Raise","name":"Side Laterals to Front Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["traps"],"instructions":["In a standing position, hold a pair of dumbbells at your side. This will be your starting position.","Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.","At the top of the exercise move the weights out in front of you, keeping your arms extended.","Lower the weights with a controlled motion.","On the next repetition, raise the weights in front of you to shoulder height before moving the weights laterally to your sides.","Lower the weights to the starting position."],"images":["Side_Laterals_to_Front_Raise/0.jpg","Side_Laterals_to_Front_Raise/1.jpg"]},{"id":"Single_Dumbbell_Raise","name":"Single Dumbbell Raise","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["forearms","traps"],"instructions":["With a wide stance, hold a dumbell with both hands, grasping the head of the dumbbell instead of the handle. Your arms should be extended and hanging at the waist. This will be your starting position.","Raise the weight until it is above shoulder level, keeping your arms extended. Your torso and hips should remain stationary throughout the movement.","Return to the starting position and repeat for the recommended amount of repetitions."],"images":["Single_Dumbbell_Raise/0.jpg","Single_Dumbbell_Raise/1.jpg"]},{"id":"Single_Leg_Glute_Bridge","name":"Single Leg Glute Bridge","equipment":"body weight","primaryMuscles":["glutes"],"secondaryMuscles":["hamstrings"],"instructions":["Lay on the floor with your feet flat and knees bent.","Raise one leg off of the ground, pulling the knee to your chest. This will be your starting position.","Execute the movement by driving through the heel, extending your hip upward and raising your glutes off of the ground.","Extend as far as possible, pause and then return to the starting position."],"images":["Single_Leg_Glute_Bridge/0.jpg","Single_Leg_Glute_Bridge/1.jpg"]},{"id":"Single-Arm_Push-Up","name":"Single-Arm Push-Up","equipment":"body weight","primaryMuscles":["chest"],"secondaryMuscles":["shoulders","triceps"],"instructions":["Begin laying prone on the ground. Move yourself into a position supporting your weight on your toes and one arm. Your working arm should be placed directly under the shoulder, fully extended. Your legs should be extended, and for this movement you may need a wider base, placing your feet further apart than in a normal push-up.","Maintain good posture, and place your free hand behind your back. This will be your starting position.","Lower yourself by allowing the elbow to flex until you touch the ground.","Descend slowly, and reverse direction be extending the arm to return to the starting position."],"images":["Single-Arm_Push-Up/0.jpg","Single-Arm_Push-Up/1.jpg"]},{"id":"Sit-Up","name":"Sit-Up","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.","Place your hands behind your head and lock them together by clasping your fingers. This is the starting position.","Elevate your upper body so that it creates an imaginary V-shape with your thighs. Breathe out when performing this part of the exercise.","Once you feel the contraction for a second, lower your upper body back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],"images":["Sit-Up/0.jpg","Sit-Up/1.jpg"]},{"id":"Speed_Band_Overhead_Triceps","name":"Speed Band Overhead Triceps","equipment":"bands","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["For this exercise anchor a band to the ground. We used an incline bench and anchored the band to the base, standing over the bench. Alternatively, this could be performed standing on the band.","To begin, pull the band behind your head, holding it with a pronated grip and your elbows up. This will be your starting position.","To perform the movement, extend through the elbow to to straighten your arms, ensuring that you keep your upper arm in place.","Pause, and then return to the starting position."],"images":["Speed_Band_Overhead_Triceps/0.jpg","Speed_Band_Overhead_Triceps/1.jpg"]},{"id":"Spell_Caster","name":"Spell Caster","equipment":"dumbbell","primaryMuscles":["abdominals"],"secondaryMuscles":["glutes","shoulders"],"instructions":["Hold a dumbbell in each hand with a pronated grip. Your feet should be wide with your hips and knees extended. This will be your starting position.","Begin the movement by pulling both of the dumbbells to one side next to your hip, rotating your torso.","Keeping your arms straight and the dumbbells parallel to the ground, rotate your torso to swing the weights to your opposite side.","Continue alternating, rotating from one side to the other until the set is complete."],"images":["Spell_Caster/0.jpg","Spell_Caster/1.jpg"]},{"id":"Spider_Crawl","name":"Spider Crawl","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":["chest","shoulders","triceps"],"instructions":["Begin in a prone position on the floor. Support your weight on your hands and toes, with your feet together and your body straight. Your arms should be bent to 90 degrees. This will be your starting position.","Initiate the movement by raising one foot off of the ground. Externally rotate the leg and bring the knee toward your elbow, as far forward as possible.","Return this leg to the starting position and repeat on the opposite side."],"images":["Spider_Crawl/0.jpg","Spider_Crawl/1.jpg"]},{"id":"Split_Squat_with_Dumbbells","name":"Split Squat with Dumbbells","equipment":"dumbbell","primaryMuscles":["quadriceps"],"secondaryMuscles":["glutes","hamstrings"],"instructions":["Position yourself into a staggered stance with the rear foot elevated and front foot forward.","Hold a dumbbell in each hand, letting them hang at the sides. This will be your starting position.","Begin by descending, flexing your knee and hip to lower your body down. Maintain good posture througout the movement. Keep the front knee in line with the foot as you perform the exercise.","At the bottom of the movement, drive through the heel to extend the knee and hip to return to the starting position."],"images":["Split_Squat_with_Dumbbells/0.jpg","Split_Squat_with_Dumbbells/1.jpg"]},{"id":"Squats_-_With_Bands","name":"Squats - With Bands","equipment":"bands","primaryMuscles":["quadriceps"],"secondaryMuscles":["calves","glutes","hamstrings","lower back"],"instructions":["To start out, make sure that the exercise band is at an even split between both the left and right side of the body. To do this, use your hands to grab both sides of the band and place both feet in the middle of the band. Your feet should be shoulder width apart from each other.","When holding the bands, they should be the same height on each side. You should be using a pronated grip (palms facing forward) and have the handles of the bands next to your face for this exercise. This is the starting position.","Slowly start to bend the knees and lower the legs so that your thighs are parallel to the floor while exhaling.","Use the heel of your feet to push your body up to the starting position as you exhale.","Repeat for the recommended amount of repetitions."],"images":["Squats_-_With_Bands/0.jpg","Squats_-_With_Bands/1.jpg"]},{"id":"Standing_Alternating_Dumbbell_Press","name":"Standing Alternating Dumbbell Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Stand with a dumbbell in each hand. Raise the dumbbells to your shoulders with your palms facing forward and your elbows pointed out. This will be your starting position.","Extend one arm to press the dumbbell straight up, keeping your off hand in place. Do not lean or jerk the weight during the movement.","After a brief pause, return the weight to the starting position.","Repeat for the opposite side, continuing to alternate between arms."],"images":["Standing_Alternating_Dumbbell_Press/0.jpg","Standing_Alternating_Dumbbell_Press/1.jpg"]},{"id":"Standing_Bent-Over_One-Arm_Dumbbell_Triceps_Extension","name":"Standing Bent-Over One-Arm Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":["shoulders"],"instructions":["With a dumbbell in one hand and the palm facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.","The upper arm should be close to the torso and parallel to the floor while the forearm is pointing towards the floor as the hand holds the weight. Tip: There should be a 90-degree angle between the forearm and the upper arm. This is your starting position.","Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions.","Switch arms and repeat the exercise."],"images":["Standing_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/0.jpg","Standing_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"Standing_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension","name":"Standing Bent-Over Two-Arm Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["With a dumbbell in each hand and the palms facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up. The upper arms should be close to the torso and parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights. Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.","Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arms are extended. Like many other arm exercises, only the forearm moves.","After a second contraction at the top, slowly lower the dumbbells back to their starting position as you inhale.","Repeat the movement for the prescribed amount of repetitions."],"images":["Standing_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/0.jpg","Standing_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"Standing_Concentration_Curl","name":"Standing Concentration Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Taking a dumbbell in your working hand, lean forward. Allow your working arm to hang perpendicular to the ground with the elbow pointing out. This will be your starting position.","Flex the elbow to curl the weight, keeping the upper arm stationary. At the top of the repetition, flex the biceps and pause.","Lower the dumbbell back to the starting position.","Repeat the movement for the prescribed amount of repetitions."],"images":["Standing_Concentration_Curl/0.jpg","Standing_Concentration_Curl/1.jpg"]},{"id":"Standing_Dumbbell_Calf_Raise","name":"Standing Dumbbell Calf Raise","equipment":"dumbbell","primaryMuscles":["calves"],"secondaryMuscles":[],"instructions":["Stand with your torso upright holding two dumbbells in your hands by your sides. Place the ball of the foot on a sturdy and stable wooden board (that is around 2-3 inches tall) while your heels extend off and touch the floor. This will be your starting position.","With the toes pointing either straight (to hit all parts equally), inwards (for emphasis on the outer head) or outwards (for emphasis on the inner head), raise the heels off the floor as you exhale by contracting the calves. Hold the top contraction for a second.","As you inhale, go back to the starting position by slowly lowering the heels.","Repeat for the recommended amount of times."],"images":["Standing_Dumbbell_Calf_Raise/0.jpg","Standing_Dumbbell_Calf_Raise/1.jpg"]},{"id":"Standing_Dumbbell_Press","name":"Standing Dumbbell Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Standing with your feet shoulder width apart, take a dumbbell in each hand. Raise the dumbbells to head height, the elbows out and about 90 degrees. This will be your starting position.","Maintaining strict technique with no leg drive or leaning back, extend through the elbow to raise the weights together directly above your head.","Pause, and slowly return the weight to the starting position."],"images":["Standing_Dumbbell_Press/0.jpg","Standing_Dumbbell_Press/1.jpg"]},{"id":"Standing_Dumbbell_Reverse_Curl","name":"Standing Dumbbell Reverse Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["To begin, stand straight with a dumbbell in each hand using a pronated grip (palms facing down). Your arms should be fully extended while your feet are shoulder width apart from each other. This is the starting position.","While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the muscle.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat for the recommended amount of repetitions."],"images":["Standing_Dumbbell_Reverse_Curl/0.jpg","Standing_Dumbbell_Reverse_Curl/1.jpg"]},{"id":"Standing_Dumbbell_Straight-Arm_Front_Delt_Raise_Above_Head","name":"Standing Dumbbell Straight-Arm Front Delt Raise Above Head","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":[],"instructions":["Hold the dumbbells in front of your thighs, palms facing your thighs.","Keep your arms straight with a slight bend at the elbows but keep them locked. This will be your starting position.","Raise the dumbbells in a semicircular motion to arm's length overhead as you exhale.","Slowly return to the starting position using the same path as you inhale.","Repeat for the recommended amount of repetitions."],"images":["Standing_Dumbbell_Straight-Arm_Front_Delt_Raise_Above_Head/0.jpg","Standing_Dumbbell_Straight-Arm_Front_Delt_Raise_Above_Head/1.jpg"]},{"id":"Standing_Dumbbell_Triceps_Extension","name":"Standing Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["To begin, stand up with a dumbbell held by both hands. Your feet should be about shoulder width apart from each other. Slowly use both hands to grab the dumbbell and lift it over your head until both arms are fully extended.","The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hands should be facing up towards the ceiling. This will be your starting position.","Keeping your upper arms close to your head with elbows in and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions."],"images":["Standing_Dumbbell_Triceps_Extension/0.jpg","Standing_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"Standing_Dumbbell_Upright_Row","name":"Standing Dumbbell Upright Row","equipment":"dumbbell","primaryMuscles":["traps"],"secondaryMuscles":["biceps","shoulders"],"instructions":["Grasp a dumbbell in each hand with a pronated (palms forward) grip that is slightly less than shoulder width. The dumbbells should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.","Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be close to the body as you move it up and the elbows should drive the motion. Continue to lift them until they nearly touch your chin. Tip: Your elbows should drive the motion. As you lift the dumbbells, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],"images":["Standing_Dumbbell_Upright_Row/0.jpg","Standing_Dumbbell_Upright_Row/1.jpg"]},{"id":"Standing_Inner-Biceps_Curl","name":"Standing Inner-Biceps Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Stand up with a dumbbell in each hand being held at arms length. The elbows should be close to the torso. Your legs should be at about shoulder's width apart from each other.","Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.","While holding the upper arms stationary, curl the weights out while contracting the biceps as you breathe out. Your wrist should turn so that when the weights are fully elevated you have supinated grip (palms facing up).","Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: Keep the forearms aligned with your outer deltoids.","Hold the contracted position for a second as you squeeze the biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate the wrists as you lower the weight in order to switch back to a neutral grip.","Repeat for the recommended amount of repetitions."],"images":["Standing_Inner-Biceps_Curl/0.jpg","Standing_Inner-Biceps_Curl/1.jpg"]},{"id":"Standing_One-Arm_Dumbbell_Curl_Over_Incline_Bench","name":"Standing One-Arm Dumbbell Curl Over Incline Bench","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Stand on the back side of an incline bench as if you were going to be a spotter for someone. Have a dumbbell in one hand and rest it across the incline bench with a supinated (palms up) grip.","Position your non lifting hand at the corner or side of the incline bench. The chest should be pressed against the top part of the incline and your feet should be pressed against the floor at a wide stance. This is the starting position.","While holding the upper arm stationary, curl the dumbbell upward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a second.","Slowly begin to bring the dumbbells back to starting position as your breathe in.","Repeat for the recommended amount of repetitions.","Switch arms while performing this exercise."],"images":["Standing_One-Arm_Dumbbell_Curl_Over_Incline_Bench/0.jpg","Standing_One-Arm_Dumbbell_Curl_Over_Incline_Bench/1.jpg"]},{"id":"Standing_One-Arm_Dumbbell_Triceps_Extension","name":"Standing One-Arm Dumbbell Triceps Extension","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["To begin, stand up with a dumbbell held in one hand. Your feet should be about shoulder width apart from each other. Now fully extend the arm with the dumbbell over your head. Tip: The small finger of your hand should be facing the ceiling and the palm of your hand should be facing forward. The dumbbell should be above your head.","This will be your starting position.","Keeping your upper arm close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearm touch your bicep. Tip: The upper arm should remain stationary and only the forearm should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions.","Switch arms and repeat the exercise."],"images":["Standing_One-Arm_Dumbbell_Triceps_Extension/0.jpg","Standing_One-Arm_Dumbbell_Triceps_Extension/1.jpg"]},{"id":"Standing_Palm-In_One-Arm_Dumbbell_Press","name":"Standing Palm-In One-Arm Dumbbell Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Start by having a dumbbell in one hand with your arm fully extended to the side using a neutral grip. Use your other arm to hold on to an incline bench to keep your balance.","Your feet should be shoulder width apart from each other. Now slowly lift the dumbbell up until you create a 90 degree angle with your arm. Note: Your forearm should be perpendicular to the floor. Continue to maintain a neutral grip throughout the entire exercise.","Slowly lift the dumbbell up until your arm is fully extended. This the starting position.","While inhaling lower the weight down until your arm is at a 90 degree angle again.","Feel the contraction for a second and then lift the weight back up towards the starting position while exhaling. Remember to hold on to the incline bench and keep your feet positioned to keep balance during the exercise.","Repeat for the recommended amount of repetitions.","Switch arms and repeat the exercise."],"images":["Standing_Palm-In_One-Arm_Dumbbell_Press/0.jpg","Standing_Palm-In_One-Arm_Dumbbell_Press/1.jpg"]},{"id":"Standing_Palms-In_Dumbbell_Press","name":"Standing Palms-In Dumbbell Press","equipment":"dumbbell","primaryMuscles":["shoulders"],"secondaryMuscles":["triceps"],"instructions":["Start by having a dumbbell in each hand with your arm fully extended to the side using a neutral grip. Your feet should be shoulder width apart from each other. Now slowly lift the dumbbells up until you create a 90 degree angle with your arms. Note: Your forearms should be perpendicular to the floor. This the starting position.","Continue to maintain a neutral grip throughout the entire exercise. Slowly lift the dumbbells up until your arms are fully extended.","While inhaling lower the weights down until your arm is at a 90 degree angle again.","Repeat for the recommended amount of repetitions."],"images":["Standing_Palms-In_Dumbbell_Press/0.jpg","Standing_Palms-In_Dumbbell_Press/1.jpg"]},{"id":"Standing_Towel_Triceps_Extension","name":"Standing Towel Triceps Extension","equipment":"body weight","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["To begin, stand up with both arms fully extended above the head holding one end of a towel with both hands. Your elbows should be in and the arms perpendicular to the floor with the palms facing each other while your feet should be shoulder width apart from each other. This is the starting position.","Now communicate with your partner so that he/she can grip the other side of the towel to apply resistance. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.","Go back to the starting position by using the triceps to raise the towel. Breathe out as you perform this step.","Repeat for the recommended amount of repetitions."],"images":["Standing_Towel_Triceps_Extension/0.jpg","Standing_Towel_Triceps_Extension/1.jpg"]},{"id":"Step-up_with_Knee_Raise","name":"Step-up with Knee Raise","equipment":"body weight","primaryMuscles":["glutes"],"secondaryMuscles":["hamstrings","quadriceps"],"instructions":["Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position.","Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can.","Reverse this motion to step down off the box, and then repeat the sequence on the opposite leg."],"images":["Step-up_with_Knee_Raise/0.jpg","Step-up_with_Knee_Raise/1.jpg"]},{"id":"Stiff-Legged_Dumbbell_Deadlift","name":"Stiff-Legged Dumbbell Deadlift","equipment":"dumbbell","primaryMuscles":["hamstrings"],"secondaryMuscles":["glutes","lower back"],"instructions":["Grasp a couple of dumbbells holding them by your side at arm's length.","Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.","Keeping the knees stationary, lower the dumbbells to over the top of your feet by bending at the waist while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Exhale as you perform this movement","Start bringing your torso up straight again by extending your hips and waist until you are back at the starting position. Inhale as you perform this movement.","Repeat for the recommended amount of repetitions."],"images":["Stiff-Legged_Dumbbell_Deadlift/0.jpg","Stiff-Legged_Dumbbell_Deadlift/1.jpg"]},{"id":"Straight-Arm_Dumbbell_Pullover","name":"Straight-Arm Dumbbell Pullover","equipment":"dumbbell","primaryMuscles":["chest"],"secondaryMuscles":["lats","shoulders","triceps"],"instructions":["Place a dumbbell standing up on a flat bench.","Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.","Grasp the dumbbell with both hands and hold it straight over your chest at arms length. Both palms should be pressing against the underside one of the sides of the dumbbell. This will be your starting position.\nCaution: Always ensure that the dumbbell used for this exercise is secure. Using a dumbbell with loose plates can result in the dumbbell falling apart and falling on your face.","While keeping your arms straight, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.","At that point, bring the dumbbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.","Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions."],"images":["Straight-Arm_Dumbbell_Pullover/0.jpg","Straight-Arm_Dumbbell_Pullover/1.jpg"]},{"id":"Tate_Press","name":"Tate Press","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":["chest","shoulders"],"instructions":["Lie down on a flat bench with a dumbbell in each hand on top of your thighs. The palms of your hand will be facing each other.","By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them in front of you at shoulder width. Note: when holding the dumbbells in front of you, make sure your arms are wider than shoulder width apart from each other using a pronated (palms forward) grip. Allow your elbows to point out. This is your starting position.","Keeping the upper arms stationary, slowly move the dumbbells in and down in a semi circular motion until they touch the upper chest while inhaling. Keep full control of the dumbbells at all times and do not move the upper arms nor rest the dumbbells on the chest.","As you breathe out, move the dumbbells up using your triceps and the same semi-circular motion but in reverse. Attempt to keep the dumbbells together as they move up. Lock your arms in the contracted position, hold for a second and then start coming down again slowly again. Tip: It should take at least twice as long to go down than to come up.","Repeat the movement for the prescribed amount of repetitions of your training program."],"images":["Tate_Press/0.jpg","Tate_Press/1.jpg"]},{"id":"Tricep_Dumbbell_Kickback","name":"Tricep Dumbbell Kickback","equipment":"dumbbell","primaryMuscles":["triceps"],"secondaryMuscles":[],"instructions":["Start with a dumbbell in each hand and your palms facing your torso. Keep your back straight with a slight bend in the knees and bend forward at the waist. Your torso should be almost parallel to the floor. Make sure to keep your head up. Your upper arms should be close to your torso and parallel to the floor. Your forearms should be pointed towards the floor as you hold the weights. There should be a 90-degree angle formed between your forearm and upper arm. This is your starting position.","Now, while keeping your upper arms stationary, exhale and use your triceps to lift the weights until the arm is fully extended. Focus on moving the forearm.","After a brief pause at the top contraction, inhale and slowly lower the dumbbells back down to the starting position.","Repeat the movement for the prescribed amount of repetitions."],"images":["Tricep_Dumbbell_Kickback/0.jpg","Tricep_Dumbbell_Kickback/1.jpg"]},{"id":"Tuck_Crunch","name":"Tuck Crunch","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["To begin, lie down on the floor or an exercise mat with your back pressed against the floor. Your arms should be lying across your sides with the palms facing down.","Your legs should be crossed by wrapping one ankle around the other. Slowly elevate your legs up in the air until your thighs are perpendicular to the floor with a slight bend at the knees. Note: Your knees and toes should be parallel to the floor as opposed to the thighs.","Move your arms from the floor and cross them so they are resting on your chest. This is the starting position.","While keeping your lower back pressed against the floor, slowly lift your torso. Remember to exhale while perform this part of the exercise.","Slowly begin to lower your torso back down to the starting position while inhaling.","Repeat for the recommended amount of repetitions."],"images":["Tuck_Crunch/0.jpg","Tuck_Crunch/1.jpg"]},{"id":"Two-Arm_Dumbbell_Preacher_Curl","name":"Two-Arm Dumbbell Preacher Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":[],"instructions":["Grab a dumbbell with each arm and place the upper arms on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.","As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.","As you exhale, use the biceps to curl the weights up until your biceps is fully contracted and the dumbbells are at shoulder height.","Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions."],"images":["Two-Arm_Dumbbell_Preacher_Curl/0.jpg","Two-Arm_Dumbbell_Preacher_Curl/1.jpg"]},{"id":"Upright_Row_-_With_Bands","name":"Upright Row - With Bands","equipment":"bands","primaryMuscles":["traps"],"secondaryMuscles":["shoulders"],"instructions":["To begin, stand on an exercise band so that tension begins at arm's length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.","Use your side shoulders to lift the handles as you exhale. The handles should be close to the body as you move them up. Continue to lift the handles until they nearly touches your chin. Tip: Your elbows should drive the motion. As you lift the handles, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.","Lower the handles back down slowly to the starting position. Inhale as you perform this portion of the movement.","Repeat for the recommended amount of repetitions."],"images":["Upright_Row_-_With_Bands/0.jpg","Upright_Row_-_With_Bands/1.jpg"]},{"id":"V-Bar_Pullup","name":"V-Bar Pullup","equipment":"body weight","primaryMuscles":["lats"],"secondaryMuscles":["biceps","middle back","shoulders"],"instructions":["Start by placing the middle of the V-bar in the middle of the pull-up bar (assuming that the pull-up station you are using does not have neutral grip handles). The V-Bar handles will be facing down so that you can hang from the pull-up bar through the use of the handles.","Once you securely place the V-bar, take a hold of the bar from each side and hang from it. Stick your chest out and lean yourself back slightly in order to better engage the lats. This will be your starting position.","Using your lats, pull your torso up while leaning your head back slightly so that you do not hit yourself with the chin-up bar. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion.","After a second hold on the contracted position, slowly lower your body back to the starting position as you breathe in.","Repeat for the prescribed number of repetitions."],"images":["V-Bar_Pullup/0.jpg","V-Bar_Pullup/1.jpg"]},{"id":"Wide-Grip_Rear_Pull-Up","name":"Wide-Grip Rear Pull-Up","equipment":"body weight","primaryMuscles":["lats"],"secondaryMuscles":["biceps","middle back","shoulders"],"instructions":["Grab the pull-up bar with the palms facing forward using a wide grip.","As you have both arms extended in front of you holding the bar, bring your torso forward and head so that there is an imaginary line from the pull-up bar to the back of your neck. This is your starting position.","Pull your torso up until the bar is near the back of your neck. To do this, draw the shoulders and upper arms down and back while slightly leaning your head forward. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.","After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.","Repeat this motion for the prescribed amount of repetitions."],"images":["Wide-Grip_Rear_Pull-Up/0.jpg","Wide-Grip_Rear_Pull-Up/1.jpg"]},{"id":"Wind_Sprints","name":"Wind Sprints","equipment":"body weight","primaryMuscles":["abdominals"],"secondaryMuscles":[],"instructions":["Hang from a pull-up bar using a pronated grip. Your arms and legs should be extended. This will be your starting position.","Begin by quickly raising one knee as high as you can. Do not swing your body or your legs. 3","Immediately reverse the motion, returning that leg to the starting position. Simultaneously raise the opposite knee as high as possible.","Continue alternating between legs until the set is complete."],"images":["Wind_Sprints/0.jpg","Wind_Sprints/1.jpg"]},{"id":"Zottman_Curl","name":"Zottman Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.","Make sure the palms of the hands are facing each other. This will be your starting position.","While holding the upper arm stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Your wrist should rotate so that you have a supinated (palms up) grip. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a second as you squeeze the biceps.","Now during the contracted position, rotate your wrist until you now have a pronated (palms facing down) grip with the thumb at a higher position than the pinky.","Slowly begin to bring the dumbbells back down using the pronated grip.","As the dumbbells close your thighs, start rotating the wrist so that you go back to a neutral (palms facing your body) grip.","Repeat for the recommended amount of repetitions."],"images":["Zottman_Curl/0.jpg","Zottman_Curl/1.jpg"]},{"id":"Zottman_Preacher_Curl","name":"Zottman Preacher Curl","equipment":"dumbbell","primaryMuscles":["biceps"],"secondaryMuscles":["forearms"],"instructions":["Grab a dumbbell in each hand and place your upper arms on top of the preacher bench or the incline bench. The dumbbells should be held at shoulder height and the elbows should be flexed. Hold the dumbbells with the palms of your hands facing down. This will be your starting position.","As you breathe in, slowly lower the dumbbells keeping the palms down until your upper arm is extended and your biceps are fully stretched.","Now rotate your wrists once you are at the bottom of the movement so that the palms of the hands are facing up.","As you exhale, use your biceps to curl the weights up until they are fully contracted and the dumbbells are at shoulder height. Again, remember that to ensure full contraction you need to bring that small finger higher than the thumb.","Squeeze the biceps hard for a second at the contracted position and rotate your wrists so that the palms are facing down again.","Repeat for the recommended amount of repetitions."],"images":["Zottman_Preacher_Curl/0.jpg","Zottman_Preacher_Curl/1.jpg"]}]
